import { Outlet, NavLink, useLocation } from 'react-router-dom';
import { useRef, useState, useCallback, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import ConsentModal from './ConsentModal';

export default function Layout() {
  return (
    <div style={{ minHeight: '100vh' }}>
      <PullToRefresh>
        <Outlet />
      </PullToRefresh>
      <BottomNav />
      <ConsentModal />
      <ChatwootWidget />
    </div>
  );
}

function ChatwootWidget() {
  const { user, isAuthenticated } = useAuth();

  // SDK ロード
  useEffect(() => {
    const baseUrl = import.meta.env.VITE_CHATWOOT_BASE_URL;
    const token = import.meta.env.VITE_CHATWOOT_TOKEN;
    if (!baseUrl || !token) return;

    const script = document.createElement('script');
    script.src = `${baseUrl}/packs/js/sdk.js`;
    script.async = true;
    window.chatwootSettings = {
      position: 'right',
      type: 'standard',
      launcherTitle: 'サポート',
    };
    script.onload = () => {
      window.chatwootSDK.run({ websiteToken: token, baseUrl });
      const style = document.createElement('style');
      style.textContent = `
        .woot-widget-bubble { bottom: 96px !important; }
        .woot-widget-holder { bottom: 96px !important; }
        .woot--close.woot-widget-bubble {
          bottom: 100px !important;
          right: 50% !important;
          transform: translateX(50%) !important;
        }
      `;
      document.head.appendChild(style);

      // iframe 内のブランディングを非表示にする
      const hidebranding = () => {
        const holder = document.querySelector('.woot-widget-holder');
        if (!holder) return;
        const iframe = holder.querySelector('iframe');
        if (!iframe) return;
        try {
          const iframeDoc = iframe.contentDocument || iframe.contentWindow?.document;
          if (iframeDoc) {
            const s = iframeDoc.createElement('style');
            s.textContent = '.branding--link, .powered-by, a[href*="chatwoot.com"], [class*="branding"] { display: none !important; }';
            iframeDoc.head.appendChild(s);
          }
        } catch { /* cross-origin — cannot inject */ }
      };
      // ウィジェット開閉時にブランディング非表示を試行
      const observer = new MutationObserver(hidebranding);
      observer.observe(document.body, { childList: true, subtree: true });
      setTimeout(hidebranding, 2000);
    };
    document.body.appendChild(script);
    return () => { script.remove(); };
  }, []);

  // ログインユーザーを Chatwoot Contact に紐付け (CRM sync + HMAC)
  useEffect(() => {
    if (!isAuthenticated || !user) return;

    async function setUserOnReady() {
      if (!window.$chatwoot) return;
      const userData = {
        name: user.user_metadata?.display_name || user.user_metadata?.name || undefined,
        email: user.email || undefined,
      };

      // HMAC identifier_hash をサーバーから取得
      try {
        const res = await fetch(`${import.meta.env.VITE_P_AICU_URL || 'https://p.aicu.jp'}/api/chatwoot/hmac`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ identifier: user.id }),
        });
        if (res.ok) {
          const { identifier_hash } = await res.json();
          userData.identifier_hash = identifier_hash;
        }
      } catch { /* HMAC なしでも setUser は動く */ }

      window.$chatwoot.setUser(user.id, userData);
    }

    if (window.$chatwoot) {
      setUserOnReady();
    } else {
      window.addEventListener('chatwoot:ready', setUserOnReady);
      return () => window.removeEventListener('chatwoot:ready', setUserOnReady);
    }
  }, [isAuthenticated, user]);

  return null;
}

function PullToRefresh({ children }) {
  const [pulling, setPulling] = useState(0);   // 0..1 progress
  const [refreshing, setRefreshing] = useState(false);
  const startY = useRef(null);

  const onTouchStart = useCallback((e) => {
    if (window.scrollY === 0) {
      startY.current = e.touches[0].clientY;
    } else {
      startY.current = null;
    }
  }, []);

  const onTouchMove = useCallback((e) => {
    if (startY.current === null || refreshing) return;
    const dy = e.touches[0].clientY - startY.current;
    if (dy > 0) {
      setPulling(Math.min(dy / 120, 1));
    }
  }, [refreshing]);

  const onTouchEnd = useCallback(() => {
    if (pulling >= 1 && !refreshing) {
      setRefreshing(true);
      setPulling(1);
      window.location.reload();
    } else {
      setPulling(0);
    }
    startY.current = null;
  }, [pulling, refreshing]);

  return (
    <div onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}>
      <div style={{
        height: pulling > 0 ? 48 * pulling : 0,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        overflow: 'hidden', transition: pulling === 0 ? 'height 0.2s' : 'none',
      }}>
        <div style={{
          width: 24, height: 24, borderRadius: '50%',
          border: '2.5px solid var(--aicu-rose)',
          borderTopColor: 'transparent',
          opacity: pulling,
          transform: `rotate(${pulling * 360}deg)`,
          transition: pulling === 0 ? 'opacity 0.2s' : 'none',
          animation: refreshing ? 'ptr-spin 0.6s linear infinite' : 'none',
        }} />
      </div>
      {children}
      {refreshing && <style>{`@keyframes ptr-spin { to { transform: rotate(360deg); } }`}</style>}
    </div>
  );
}

function BottomNav() {
  const { isAuthenticated } = useAuth();
  const location = useLocation();

  const navItems = [
    { path: '/', label: 'Service', icon: ServiceIcon },
    { path: '/create/voice', label: 'Create', icon: CreateIcon },
    { path: '/media', label: 'Media', icon: MediaIcon },
    { path: isAuthenticated ? '/profile' : '/login', label: isAuthenticated ? '設定' : 'ログイン', icon: ProfileIcon },
  ];

  const isActive = (path) => {
    if (path === '/') return location.pathname === '/';
    return location.pathname.startsWith(path);
  };

  return (
    <nav style={{
      position: 'fixed',
      bottom: 20,
      left: '50%',
      transform: 'translateX(-50%)',
      zIndex: 100,
      display: 'flex',
      alignItems: 'center',
      gap: 2,
      padding: 4,
      borderRadius: 80,
      background: 'rgba(22,22,23,0.72)',
      backdropFilter: 'blur(16px) saturate(1.6)',
      WebkitBackdropFilter: 'blur(16px) saturate(1.6)',
      border: '1px solid rgba(255,255,255,0.08)',
      boxShadow: '0 8px 32px rgba(0,0,0,0.24), inset 0 0.5px 0 rgba(255,255,255,0.06)',
    }}>
      {navItems.map(item => {
        const active = !item.disabled && isActive(item.path);
        return (
          <NavLink
            key={item.label}
            to={item.disabled ? '#' : item.path}
            end={item.path === '/'}
            onClick={e => item.disabled && e.preventDefault()}
            style={{
              position: 'relative',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: 8,
              padding: '10px 16px',
              minWidth: 44,
              minHeight: 44,
              borderRadius: 72,
              border: 'none',
              background: active ? 'rgba(255,255,255,0.09)' : 'none',
              textDecoration: 'none',
              cursor: item.disabled ? 'default' : 'pointer',
              color: item.disabled
                ? 'rgba(255,255,255,0.25)'
                : active
                  ? '#ffffff'
                  : 'rgba(255,255,255,0.5)',
              transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
              WebkitTapHighlightColor: 'transparent',
            }}
          >
            <item.icon />
            <span style={{
              fontSize: 13,
              fontWeight: 500,
              lineHeight: 1,
              letterSpacing: '-0.01em',
              whiteSpace: 'nowrap',
              maxWidth: active ? 80 : 0,
              opacity: active ? 1 : 0,
              overflow: 'hidden',
              transition: 'max-width 0.25s ease, opacity 0.2s ease',
              paddingRight: active ? 2 : 0,
            }}>
              {item.label}
            </span>
          </NavLink>
        );
      })}
    </nav>
  );
}

