              <div style={{ fontSize: 13, color: 'var(--text-primary)', lineHeight: 1.5 }}>
                {row.value}
              </div>
            </div>
          ))}
        </div>

        {/* Back link */}
        <Link
          to="/e"
          style={{
            display: 'inline-flex',
            alignItems: 'center',
            gap: 6,
            padding: '10px 16px',
            borderRadius: 'var(--radius-sm)',
            background: 'var(--bg-card)',
            boxShadow: 'var(--shadow-sm)',
            textDecoration: 'none',
            fontSize: 13,
            fontWeight: 600,
            color: 'var(--aicu-rose-dark)',
