import { useEffect } from 'react';
import { useParams, Navigate, Link } from 'react-router-dom';
import { getEventByShortcode } from '../data/events';
import CreateVoice from './CreateVoice';

export default function EventArchive() {
  const { slug } = useParams();
  const event = getEventByShortcode(slug);

  // Not found → redirect to event list
  if (!event) {
    return <Navigate to="/e" replace />;
  }

  // Live event → full-page navigation to static HTML
  if (event.status === 'live' && event.staticPath) {
    useEffect(() => {
      window.location.href = event.staticPath;
    }, []);
    return null;
  }

  // VoiceAudition → render CreateVoice with archived banner
  if (event.shortcode === 'VoiceAudition') {
    return <CreateVoice archived />;
  }

  // Generic archive
  return <GenericArchive event={event} />;
}

function GenericArchive({ event }) {
  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/e" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>← Events</span>
          </Link>
          <span style={styles.headerTitle}>{event.emoji} {event.title}</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '0 16px 40px' }}>
        {/* Ended banner */}
        <div style={{
          margin: '20px 0 16px',
          padding: '10px 14px',
          borderRadius: 'var(--radius-sm)',
          background: 'var(--bg-card)',
          border: '1px solid var(--border)',
          textAlign: 'center',
          fontSize: 13,
          fontWeight: 600,
          color: 'var(--text-tertiary)',
        }}>
          このイベントは終了しました
        </div>

        {/* Image */}
        {event.image && (
          <img
            src={event.image}
            alt={event.title}
            style={{
              width: '100%',
              height: 'auto',
              borderRadius: 'var(--radius)',
              boxShadow: 'var(--shadow-sm)',
              marginBottom: 16,
            }}
          />
        )}

        {/* Info table */}
        <div style={{
          borderRadius: 'var(--radius)',
          background: 'var(--bg-card)',
          boxShadow: 'var(--shadow-sm)',
          overflow: 'hidden',
          marginBottom: 20,
        }}>
          {[
            { label: 'タイトル', value: `${event.emoji} ${event.title}` },
            { label: '期間', value: `${event.dateStart} 〜 ${event.dateEnd}` },
            { label: '会場', value: event.venue },
            { label: '概要', value: event.description },
          ].map((row, i, arr) => (
            <div key={row.label} style={{
              display: 'flex',
              padding: '12px 16px',
              borderBottom: i < arr.length - 1 ? '0.5px solid var(--border)' : 'none',
              gap: 12,
            }}>
              <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-tertiary)', minWidth: 64, flexShrink: 0 }}>
                {row.label}
              </div>
              <div style={{ fontSize: 13, color: 'var(--text-primary)', lineHeight: 1.5 }}>
                {row.value}
              </div>
            </div>
          ))}
        </div>

        {/* Back link */}
        <Link
          to="/e"
          style={{
            display: 'inline-flex',
            alignItems: 'center',
            gap: 6,
            padding: '10px 16px',
            borderRadius: 'var(--radius-sm)',
            background: 'var(--bg-card)',
            boxShadow: 'var(--shadow-sm)',
            textDecoration: 'none',
            fontSize: 13,
            fontWeight: 600,
            color: 'var(--aicu-rose-dark)',
          }}
        >
          ← イベント一覧へ戻る
        </Link>

        {/* Footer */}
        <footer style={{
          padding: '28px 0 16px',
          textAlign: 'center',
          fontSize: 11,
          color: 'var(--text-tertiary)',
        }}>
          <p>Powered by <a href="https://aicu.ai" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>AICU Inc.</a></p>
        </footer>
      </main>
    </div>
  );
}

