              display: 'flex',
              padding: '12px 16px',
              borderBottom: i < arr.length - 1 ? '0.5px solid var(--border)' : 'none',
              gap: 12,
            }}>
              <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-tertiary)', minWidth: 64, flexShrink: 0 }}>
                {row.label}
              </div>
              <div style={{ fontSize: 13, color: 'var(--text-primary)', lineHeight: 1.5 }}>
                {row.value}
              </div>
            </div>
          ))}
        </div>

