export const events = [
  {
    shortcode: 'Fes26Halu',
    title: 'AICU はるフェス 2026',
    emoji: '🌸',
    status: 'live',
    dateStart: '2026-03-06',
    dateEnd: '2026-03-08',
    venue: '新宿 Crypto Lounge GOX',
    description: 'AI×クリエイティブの3日間フェスティバル',
    image: '/e/Fes26Halu/img/og.png',
    tags: ['festival', 'in-person'],
    staticPath: '/e/Fes26Halu/',
    // KPI: capacity, registrations count, etc. are managed server-side (p.aicu.jp)
    capacity: 100,
    links: [
      { icon: '📰', label: 'プレスリリース (PRTIMES)', url: 'https://prtimes.jp/main/html/searchrlp/company_id/141020' },
      { icon: '📝', label: '特設記事 (note)', url: 'https://note.com/aicu/n/naa1c4f89cfe8' },
    ],
  },
  {
    shortcode: 'VoiceAudition',
    title: 'AiCuty Voice Audition',
    emoji: '🎤',
    status: 'archive',
    dateStart: '2026-01-01',
    dateEnd: '2026-02-15',
    venue: 'Online',
    description: 'Qwen3-TTS で AiCuty のボイスを生成',
    image: '/CoverArtWithText.webp',
    tags: ['online', 'voice', 'aicuty'],
    links: [
      { icon: '📝', label: '特設記事 (note)', url: 'https://note.com/aicu/n/naa1c4f89cfe8' },
      { icon: '📚', label: 'AiCuty ガイドライン', url: 'https://www.aicu.jp/terms/aicuty-guideline' },
    ],
  },
];

export function getEventByShortcode(slug) {
  return events.find((e) => e.shortcode === slug) || null;
}

export function getEventsByStatus(status) {
  return events.filter((e) => e.status === status);
}

export function getSortedEvents() {
  const order = { live: 0, preview: 1, archive: 2 };
  return [...events].sort(
    (a, b) => (order[a.status] ?? 9) - (order[b.status] ?? 9) || b.dateStart.localeCompare(a.dateStart),
  );
}

import { useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getSortedEvents } from '../data/events';

const statusLabel = { live: 'LIVE', preview: 'Coming soon', archive: 'Archive' };
const statusColor = {
  live: { bg: '#dcfce7', text: '#166534' },
  preview: { bg: '#fef9c3', text: '#854d0e' },
  archive: { bg: 'var(--bg-card)', text: 'var(--text-tertiary)' },
};

export default function Events() {
  const sorted = getSortedEvents();
  const live = sorted.filter((e) => e.status === 'live');
  const preview = sorted.filter((e) => e.status === 'preview');
  const archive = sorted.filter((e) => e.status === 'archive');

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>← AICU</span>
          </Link>
          <span style={styles.headerTitle}>Events</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '0 16px 40px' }}>
        {/* Live events — large cards */}
        {live.length > 0 && (
          <section style={{ marginTop: 20, marginBottom: 24 }}>
            <SectionTitle>Live</SectionTitle>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              {live.map((ev) => (
                <a
                  key={ev.shortcode}
                  href={ev.staticPath}
                  onClick={() => {
                    if (window.gtag) {
                      window.gtag('event', 'event_click', {
                        event_shortcode: ev.shortcode,
                        event_status: ev.status,
                        event_title: ev.title,
                      });
                    }
                  }}
                  style={{
                    display: 'block',
                    borderRadius: 'var(--radius)',
                    overflow: 'hidden',
                    background: 'var(--bg-card)',
                    boxShadow: 'var(--shadow-sm)',
                    textDecoration: 'none',
                    border: '1px solid var(--border)',
                  }}
                >
                  {ev.image && (
                    <img
                      src={ev.image}
                      alt={ev.title}
                      style={{ width: '100%', height: 'auto', display: 'block' }}
                    />
                  )}
                  <div style={{ padding: '14px 16px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
                      <span style={{
                        padding: '2px 8px',
                        borderRadius: 6,
                        fontSize: 10,
                        fontWeight: 700,
                        background: statusColor.live.bg,
                        color: statusColor.live.text,
                      }}>
                        LIVE
                      </span>
                      <span style={{ fontSize: 11, color: 'var(--text-tertiary)' }}>
                        {formatRange(ev.dateStart, ev.dateEnd)}
                      </span>
                    </div>
                    <div style={{ fontSize: 16, fontWeight: 700, color: 'var(--text-primary)' }}>
                      {ev.emoji} {ev.title}
                    </div>
                    <div style={{ fontSize: 12, color: 'var(--text-secondary)', marginTop: 4 }}>
                      📍 {ev.venue} — {ev.description}
                    </div>
                  </div>
                </a>
              ))}
            </div>
          </section>
        )}

        {/* Preview events */}
        {preview.length > 0 && (
          <section style={{ marginBottom: 24 }}>
            <SectionTitle>Coming soon</SectionTitle>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {preview.map((ev) => (
                <div
                  key={ev.shortcode}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 10,
                    padding: '12px 14px',
                    borderRadius: 'var(--radius-sm)',
                    background: 'var(--bg-card)',
                    boxShadow: 'var(--shadow-sm)',
                    border: '1px solid var(--border)',
                    opacity: 0.8,
                  }}
                >
                  <span style={{ fontSize: 24 }}>{ev.emoji}</span>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                      <span style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)' }}>
                        {ev.title}
                      </span>
                      <Badge status="preview" />
                    </div>
                    <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginTop: 2 }}>
                      {ev.description}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>
        )}

        {/* Archive events */}
        {archive.length > 0 && (
          <section style={{ marginBottom: 24 }}>
            <SectionTitle>Archive</SectionTitle>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {archive.map((ev) => (
                <Link
                  key={ev.shortcode}
                  to={`/e/${ev.shortcode}`}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 10,
                    padding: '12px 14px',
                    borderRadius: 'var(--radius-sm)',
                    background: 'var(--bg-card)',
                    boxShadow: 'var(--shadow-sm)',
                    textDecoration: 'none',
                    border: '1px solid var(--border)',
                  }}
                >
                  <span style={{ fontSize: 24 }}>{ev.emoji}</span>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                      <span style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)' }}>
                        {ev.title}
                      </span>
                      <Badge status="archive" />
                    </div>
                    <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginTop: 2 }}>
                      {formatRange(ev.dateStart, ev.dateEnd)} — {ev.venue}
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          </section>
        )}

        {/* Footer */}
        <footer style={{
          padding: '28px 0 16px',
          textAlign: 'center',
          fontSize: 11,
          color: 'var(--text-tertiary)',
        }}>
          <p>Powered by <a href="https://aicu.ai" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>AICU Inc.</a></p>
        </footer>
      </main>
    </div>
  );
}

function Badge({ status }) {
  const sc = statusColor[status];
  return (
    <span style={{
      padding: '1px 6px',
      borderRadius: 6,
      fontSize: 9,
      fontWeight: 700,
      background: sc.bg,
      color: sc.text,
      border: status === 'archive' ? '1px solid var(--border)' : 'none',
    }}>
      {statusLabel[status]}
    </span>
  );
}

function SectionTitle({ children }) {
  return (
    <h2 style={{
      fontSize: 13,
      fontWeight: 700,
      color: 'var(--text-tertiary)',
      textTransform: 'uppercase',
      letterSpacing: '0.06em',
      marginBottom: 12,
    }}>
      {children}
    </h2>
  );
}

function formatRange(start, end) {
  const s = new Date(start + 'T00:00:00');
  const e = new Date(end + 'T00:00:00');
  const fmt = (d) => `${d.getMonth() + 1}/${d.getDate()}`;
  return s.getFullYear() === e.getFullYear()
    ? `${s.getFullYear()}/${fmt(s)}–${fmt(e)}`
    : `${s.getFullYear()}/${fmt(s)}–${e.getFullYear()}/${fmt(e)}`;
}

const styles = {
  header: {
    position: 'sticky',
    top: 0,
    zIndex: 50,
    background: 'var(--bg-nav)',
    backdropFilter: 'blur(20px) saturate(180%)',
    WebkitBackdropFilter: 'blur(20px) saturate(180%)',
    borderBottom: '0.5px solid var(--border)',
  },
  headerInner: {
    maxWidth: 640,
    margin: '0 auto',
    padding: '14px 16px',
    display: 'flex',
    alignItems: 'center',
    gap: 10,
  },
  logo: {
    fontFamily: "'Outfit', sans-serif",
    fontSize: 18,
    fontWeight: 800,
    color: 'var(--aicu-rose)',
    letterSpacing: '-0.02em',
  },
  headerTitle: {
    fontSize: 15,
    fontWeight: 600,
    color: 'var(--text-primary)',
  },
};

