import { Link } from 'react-router-dom';
import { getSortedEvents } from '../data/events';

const statusLabel = { live: 'LIVE', preview: 'Coming soon', archive: 'Archive' };
const statusColor = {
  live: { bg: '#dcfce7', text: '#166534' },
  preview: { bg: '#fef9c3', text: '#854d0e' },
  archive: { bg: 'var(--bg-card)', text: 'var(--text-tertiary)' },
};

export default function Events() {
  const sorted = getSortedEvents();

  return (
    <div style={{ minHeight: '100vh' }}>
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>← AICU</span>
          </Link>
          <span style={styles.headerTitle}>Events</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '16px 16px 40px' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {sorted.map((ev) => (
            <EventCard key={ev.shortcode} event={ev} />
          ))}
        </div>

        <footer style={{
          padding: '28px 0 16px',
          textAlign: 'center',
          fontSize: 11,
          color: 'var(--text-tertiary)',
        }}>
          <p>Powered by <a href="https://aicu.ai" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>AICU Inc.</a></p>
        </footer>
      </main>
    </div>
  );
}

function EventCard({ event: ev }) {
  const isLive = ev.status === 'live';
  const isPreview = ev.status === 'preview';
  const sc = statusColor[ev.status];

  /* ─── Live: バナー画像を上部に大きく表示 ─── */
  if (isLive) {
    const card = (
      <div style={{
        borderRadius: 'var(--radius)',
        overflow: 'hidden',
        background: 'var(--bg-card)',
        boxShadow: 'var(--shadow-sm)',
        border: '1.5px solid var(--aicu-rose)',
      }}>
        {ev.image && (
          <img src={ev.image} alt={ev.title} style={{ width: '100%', height: 'auto', display: 'block' }} />
        )}
        <div style={{ padding: '12px 14px' }}>
          <Badge status="live" />
          <div style={{ fontSize: 16, fontWeight: 700, color: 'var(--text-primary)', lineHeight: 1.4, margin: '8px 0 6px' }}>
            {ev.emoji} {ev.title}
          </div>
          <InfoRows ev={ev} />
          <Desc ev={ev} />
          <div style={{ marginTop: 10, fontSize: 12, fontWeight: 600, color: 'var(--aicu-rose-dark)' }}>詳細 →</div>
        </div>
      </div>
    );

    return (
      <a
        href={ev.staticPath}
        style={{ textDecoration: 'none', display: 'block' }}
        onClick={() => {
          if (window.gtag) window.gtag('event', 'event_click', { event_shortcode: ev.shortcode, event_status: ev.status, event_title: ev.title });
        }}
      >
        {card}
      </a>
    );
  }

  /* ─── Archive / Preview: 左テキスト + 右カバーアート ─── */
  const card = (
    <div style={{
      display: 'flex',
      borderRadius: 'var(--radius)',
      overflow: 'hidden',
      background: 'var(--bg-card)',
      boxShadow: 'var(--shadow-sm)',
      border: '1px solid var(--border)',
      opacity: isPreview ? 0.7 : 1,
    }}>
      {/* Left: info */}
      <div style={{ flex: 1, padding: '12px 14px', minWidth: 0 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap', marginBottom: 6 }}>
          <Badge status={ev.status} />
          {ev.tags.includes('members') && (
            <span style={{
              padding: '2px 6px', borderRadius: 6, fontSize: 9, fontWeight: 600,
              background: 'var(--aicu-rose-light)', color: 'var(--aicu-rose-dark)',
            }}>
              会員特典
            </span>
          )}
        </div>
        <div style={{ fontSize: 14, fontWeight: 700, color: 'var(--text-primary)', lineHeight: 1.4, marginBottom: 6 }}>
          {ev.emoji} {ev.title}
        </div>
        <InfoRows ev={ev} />
        <Desc ev={ev} />
        <div style={{ marginTop: 8, fontSize: 12, fontWeight: 600, color: 'var(--aicu-rose-dark)' }}>詳細 →</div>
      </div>

      {/* Right: cover art */}
      {ev.image && (
        <div style={{ width: 120, flexShrink: 0, alignSelf: 'stretch' }}>
          <img
            src={ev.image}
            alt={ev.title}
            style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }}
          />
        </div>
      )}
    </div>
  );

  if (isPreview) return card;

  return (
    <Link to={`/e/${ev.shortcode}`} style={{ textDecoration: 'none', display: 'block' }}>
      {card}
    </Link>
  );
}

/* ─── Shared sub-components ─── */

function Badge({ status }) {
  const sc = statusColor[status];
  return (
    <span style={{
      padding: '2px 8px', borderRadius: 6, fontSize: 10, fontWeight: 700,
      background: sc.bg, color: sc.text,
      border: status === 'archive' ? '1px solid var(--border)' : 'none',
    }}>
      {statusLabel[status]}
    </span>
  );
}

function InfoRows({ ev }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 2, fontSize: 11, color: 'var(--text-secondary)', lineHeight: 1.5 }}>
      <div style={{ display: 'flex', gap: 5 }}>
        <span style={styles.infoIcon}>📅</span>
        <span>{ev.dateLabel}</span>
      </div>
      <div style={{ display: 'flex', gap: 5 }}>
        <span style={styles.infoIcon}>📍</span>
        <span>{ev.venue}</span>
      </div>
      {ev.organizer && (
        <div style={{ display: 'flex', gap: 5 }}>
          <span style={styles.infoIcon}>🏢</span>
          <span>{ev.organizer}</span>
        </div>
      )}
    </div>
  );
}

function Desc({ ev }) {
  return (
    <p style={{ fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.5, marginTop: 6, marginBottom: 0 }}>
      {ev.description}
    </p>
  );
}

/* ─── Styles ─── */

const styles = {
  header: {
    position: 'sticky', top: 0, zIndex: 50,
    background: 'var(--bg-nav)',
    backdropFilter: 'blur(20px) saturate(180%)',
    WebkitBackdropFilter: 'blur(20px) saturate(180%)',
    borderBottom: '0.5px solid var(--border)',
  },
  headerInner: {
    maxWidth: 640, margin: '0 auto', padding: '14px 16px',
    display: 'flex', alignItems: 'center', gap: 10,
  },
  logo: {
    fontFamily: "'Outfit', sans-serif", fontSize: 18, fontWeight: 800,
    color: 'var(--aicu-rose)', letterSpacing: '-0.02em',
  },
  headerTitle: {
    fontSize: 15, fontWeight: 600, color: 'var(--text-primary)',
  },
  infoIcon: {
    width: 14, flexShrink: 0, textAlign: 'center', fontSize: 11,
  },
};

