import { Link } from 'react-router-dom';
import { getSortedEvents } from '../data/events';

const statusLabel = { live: 'LIVE', preview: 'Coming soon', archive: 'Archive' };
const statusColor = {
  live: { bg: '#dcfce7', text: '#166534' },
  preview: { bg: '#fef9c3', text: '#854d0e' },
  archive: { bg: 'var(--bg-card)', text: 'var(--text-tertiary)' },
};

export default function Events() {
  const sorted = getSortedEvents();

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>← AICU</span>
          </Link>
          <span style={styles.headerTitle}>Events</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '16px 16px 40px' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {sorted.map((ev) => (
            <EventCard key={ev.shortcode} event={ev} />
          ))}
        </div>

        {/* Footer */}
        <footer style={{
          padding: '28px 0 16px',
          textAlign: 'center',
          fontSize: 11,
          color: 'var(--text-tertiary)',
        }}>
          <p>Powered by <a href="https://aicu.ai" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>AICU Inc.</a></p>
        </footer>
      </main>
    </div>
  );
}

function EventCard({ event: ev }) {
  const isLive = ev.status === 'live';
  const isPreview = ev.status === 'preview';
  const sc = statusColor[ev.status];

  // live → <a href> (static HTML), archive → <Link>, preview → no link
  const cardContent = (
    <div style={{
      borderRadius: 'var(--radius)',
      overflow: 'hidden',
      background: 'var(--bg-card)',
      boxShadow: 'var(--shadow-sm)',
      border: isLive ? '1.5px solid var(--aicu-rose)' : '1px solid var(--border)',
      opacity: isPreview ? 0.7 : 1,
    }}>
      {/* Banner image */}
      {ev.image && (
        <img
          src={ev.image}
          alt={ev.title}
          style={{ width: '100%', height: 'auto', display: 'block' }}
        />
      )}

      {/* 5W1H info */}
      <div style={{ padding: '12px 14px' }}>
        {/* Status badge + tags */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 8, flexWrap: 'wrap' }}>
          <span style={{
            padding: '2px 8px',
            borderRadius: 6,
            fontSize: 10,
            fontWeight: 700,
            background: sc.bg,
            color: sc.text,
            border: ev.status === 'archive' ? '1px solid var(--border)' : 'none',
          }}>
            {statusLabel[ev.status]}
          </span>
          {ev.tags.includes('members') && (
            <span style={{
              padding: '2px 6px',
              borderRadius: 6,
              fontSize: 9,
              fontWeight: 600,
              background: 'var(--aicu-rose-light)',
              color: 'var(--aicu-rose-dark)',
            }}>
              会員特典
            </span>
          )}
        </div>

        {/* What: title */}
        <div style={{ fontSize: 15, fontWeight: 700, color: 'var(--text-primary)', lineHeight: 1.4, marginBottom: 8 }}>
          {ev.emoji} {ev.title}
        </div>

        {/* Compact 5W1H rows */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 3, fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.5 }}>
          {/* When */}
          <div style={{ display: 'flex', gap: 6 }}>
            <span style={styles.infoIcon}>📅</span>
            <span>{ev.dateLabel}</span>
          </div>
          {/* Where */}
          <div style={{ display: 'flex', gap: 6 }}>
            <span style={styles.infoIcon}>📍</span>
            <span>{ev.venue}</span>
          </div>
          {/* Who */}
          {ev.organizer && (
            <div style={{ display: 'flex', gap: 6 }}>
              <span style={styles.infoIcon}>🏢</span>
              <span>{ev.organizer}</span>
            </div>
          )}
          {/* Why / What: description */}
          <div style={{ display: 'flex', gap: 6 }}>
            <span style={styles.infoIcon}>💡</span>
            <span>{ev.description}</span>
          </div>
        </div>

        {/* Detail link */}
        <div style={{ marginTop: 10, fontSize: 12, fontWeight: 600, color: 'var(--aicu-rose-dark)' }}>
          詳細 →
        </div>
      </div>
    </div>
  );

  if (isLive && ev.staticPath) {
    return (
      <a
        href={ev.staticPath}
        style={{ textDecoration: 'none', display: 'block' }}
        onClick={() => {
          if (window.gtag) {
            window.gtag('event', 'event_click', {
              event_shortcode: ev.shortcode,
              event_status: ev.status,
              event_title: ev.title,
            });
          }
        }}
      >
        {cardContent}
      </a>
    );
  }

  if (isPreview) {
    return cardContent;
  }

  // archive
  return (
    <Link to={`/e/${ev.shortcode}`} style={{ textDecoration: 'none', display: 'block' }}>
      {cardContent}
    </Link>
  );
}

const styles = {
  header: {
    position: 'sticky',
    top: 0,
    zIndex: 50,
    background: 'var(--bg-nav)',
    backdropFilter: 'blur(20px) saturate(180%)',
    WebkitBackdropFilter: 'blur(20px) saturate(180%)',
    borderBottom: '0.5px solid var(--border)',
  },
  headerInner: {
    maxWidth: 640,
    margin: '0 auto',
    padding: '14px 16px',
    display: 'flex',
    alignItems: 'center',
    gap: 10,
  },
  logo: {
    fontFamily: "'Outfit', sans-serif",
    fontSize: 18,
    fontWeight: 800,
    color: 'var(--aicu-rose)',
    letterSpacing: '-0.02em',
  },
  headerTitle: {
    fontSize: 15,
    fontWeight: 600,
    color: 'var(--text-primary)',
  },
  infoIcon: {
    width: 16,
    flexShrink: 0,
    textAlign: 'center',
    fontSize: 12,
  },
};

