import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { characters } from '../data/characters';

const TOOL_URL = 'https://qwen3tts.aicu.jp';

const jsonLd = {
  '@context': 'https://schema.org',
  '@type': 'SoftwareApplication',
  name: 'AICU AI Voice — AiCuty キャラクターボイス',
  description: 'Qwen3-TTSで推しの声を作ろう！AiCuty 5人に、あなたの解釈で声を与えてください。',
  url: 'https://aicu.jp/create/voice',
  applicationCategory: 'MultimediaApplication',
  operatingSystem: 'Web',
  image: 'https://aicu.jp/CoverArtWithText.webp',
  offers: { '@type': 'Offer', price: '0', priceCurrency: 'JPY', availability: 'https://schema.org/InStock' },
  provider: { '@type': 'Organization', name: 'AICU Japan株式会社', url: 'https://aicu.jp' },
};

export default function CreateVoice({ archived = false }) {
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    const script = document.createElement('script');
    script.type = 'application/ld+json';
    script.textContent = JSON.stringify(jsonLd);
    document.head.appendChild(script);
    return () => script.remove();
  }, []);

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>AICU</span>
          </Link>
          <span style={styles.headerTitle}>Create / Voice</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '0 16px 40px' }}>
        {/* Archived banner */}
        {archived && (
          <div style={{
            margin: '16px 0 0',
            padding: '10px 14px',
