                </div>
              </div>
            ))}
          </div>
        </section>

        {/* How to participate */}
        <section style={{ marginBottom: 32 }}>
          <SectionTitle>参加方法</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {steps.map((step, i) => (
              <div key={i} style={{
                display: 'flex',
