                background: 'var(--bg-card)',
                boxShadow: 'var(--shadow-sm)',
                alignItems: 'flex-start',
              }}>
                <span style={{
                  width: 28,
                  height: 28,
                  borderRadius: '50%',
                  background: 'var(--aicu-rose)',
                  color: '#fff',
