import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { characters } from '../data/characters';
import Footer from '../components/Footer';

const TOOL_URL = 'https://qwen3tts.aicu.jp';

const jsonLd = {
  '@context': 'https://schema.org',
  '@type': 'SoftwareApplication',
  name: 'AICU AI Voice — AiCuty キャラクターボイス',
  description: 'Qwen3-TTSで推しの声を作ろう！AiCuty 5人に、あなたの解釈で声を与えてください。',
  url: 'https://aicu.jp/create/voice',
  applicationCategory: 'MultimediaApplication',
  operatingSystem: 'Web',
  image: 'https://aicu.jp/CoverArtWithText.webp',
  offers: { '@type': 'Offer', price: '0', priceCurrency: 'JPY', availability: 'https://schema.org/InStock' },
  provider: { '@type': 'Organization', name: 'AICU Japan株式会社', url: 'https://aicu.jp' },
};

export default function CreateVoice({ archived = false }) {
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    const script = document.createElement('script');
    script.type = 'application/ld+json';
    script.textContent = JSON.stringify(jsonLd);
    document.head.appendChild(script);
    return () => script.remove();
  }, []);

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>AICU</span>
          </Link>
          <span style={styles.headerTitle}>Create / Voice</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '0 16px 40px' }}>
        {/* Archived banner */}
        {archived && (
          <div style={{
            margin: '16px 0 0',
            padding: '10px 14px',
            borderRadius: 'var(--radius-sm)',
            background: 'var(--bg-card)',
            border: '1px solid var(--border)',
            textAlign: 'center',
            fontSize: 13,
            fontWeight: 600,
            color: 'var(--text-tertiary)',
          }}>
            このイベントは終了しました — <Link to="/e" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>イベント一覧</Link>
          </div>
        )}

        {/* Hero */}
        <section style={{ textAlign: 'center', padding: '20px 0 16px' }}>
          <div style={{
            display: 'inline-block',
            padding: '5px 14px',
            borderRadius: 20,
            background: 'linear-gradient(135deg, #FFB7C5, #9370DB)',
            color: '#fff',
            fontSize: 11,
            fontWeight: 700,
            letterSpacing: '0.04em',
            marginBottom: 10,
          }}>
            AiCuty Voice Audition
          </div>
          <h1 style={{ fontSize: 20, fontWeight: 700, color: 'var(--text-primary)', lineHeight: 1.4 }}>
            推しの声を、あなたが決める。
          </h1>
          <p style={{ fontSize: 13, color: 'var(--text-secondary)', marginTop: 6, lineHeight: 1.5 }}>
            AI音声モデル「Qwen3-TTS」で AiCuty のボイスを生成
          </p>
          <div style={{
            display: 'inline-flex',
            gap: 6,
            marginTop: 10,
            fontSize: 11,
          }}>
            <span style={{
              padding: '3px 10px',
              borderRadius: 8,
              background: 'var(--aicu-rose-light)',
              color: 'var(--aicu-rose-dark)',
              fontWeight: 600,
            }}>
              Basic会員以上は無料
            </span>
            <span style={{
              padding: '3px 10px',
              borderRadius: 8,
              background: 'var(--bg-card)',
              border: '1px solid var(--border)',
              color: 'var(--text-tertiary)',
            }}>
              #AiCuty でXに投稿
            </span>
          </div>
        </section>

        {/* Cover image */}
        <img
          src="/CoverArtWithText.webp"
          alt="AiCuty キャラクターボイスオーディション"
          width={640}
          height={357}
          style={{
            width: '100%',
            height: 'auto',
