              <div key={row.label} style={{
                display: 'flex',
                padding: '12px 16px',
                borderBottom: i < companyInfo.length - 1 ? '0.5px solid var(--border)' : 'none',
                gap: 12,
              }}>
                <div style={{
                  fontSize: 12,
                  fontWeight: 600,
                  color: 'var(--text-tertiary)',
                  minWidth: 80,
                  flexShrink: 0,
                }}>
                  {row.label}
                </div>
                <div style={{
                  fontSize: 13,
                  color: 'var(--text-primary)',
                  lineHeight: 1.5,
                }}>
                  {row.value}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Partners */}
        <section style={{ marginBottom: 40 }}>
          <SectionTitle>パートナー</SectionTitle>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
            {partners.map((p) => (
              <div key={p.name} style={{
                flex: '1 1 calc(50% - 5px)',
                padding: '16px 14px',
                borderRadius: 'var(--radius)',
                background: 'var(--bg-card)',
                boxShadow: 'var(--shadow-sm)',
                textAlign: 'center',
              }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)' }}>
                  {p.name}
                </div>
                <div style={{ fontSize: 11, color: 'var(--text-tertiary)', marginTop: 4 }}>
                  {p.role}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Footer */}
        <footer style={{
          padding: '28px 0 16px',
          textAlign: 'center',
          fontSize: 11,
          color: 'var(--text-tertiary)',
        }}>
          <div style={{
            display: 'flex',
            flexWrap: 'wrap',
            justifyContent: 'center',
            gap: '4px 14px',
            marginBottom: 14,
          }}>
            {footerLinks.map((f) => (
              <a
                key={f.label}
