    const script = document.createElement('script');
    script.type = 'application/ld+json';
    script.textContent = JSON.stringify(jsonLd);
    document.head.appendChild(script);
    return () => script.remove();
  }, []);

  return (
    <div style={{ minHeight: '100vh' }}>
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>← AICU</span>
          </Link>
          <span style={styles.headerTitle}>会社情報</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '0 16px 40px' }}>
        {/* Hero */}
        <section style={{ textAlign: 'center', padding: '24px 0 20px' }}>
          <h1 style={{ fontSize: 22, fontWeight: 800, color: 'var(--text-primary)', lineHeight: 1.4 }}>
            AICU Japan株式会社
          </h1>
          <p style={{ fontSize: 13, color: 'var(--text-secondary)', marginTop: 6, lineHeight: 1.6 }}>
            クリエイティブAI時代に「つくる人をつくる」
          </p>
          <div style={{
            display: 'inline-block',
            marginTop: 10,
            padding: '4px 12px',
            borderRadius: 8,
            background: 'var(--aicu-rose-light)',
            color: 'var(--aicu-rose-dark)',
            fontSize: 11,
            fontWeight: 600,
          }}>
            東京科学大学認定ベンチャー企業 第7号
          </div>
        </section>

        {/* Company info table */}
        <section style={{ marginBottom: 24 }}>
          <SectionTitle>会社概要</SectionTitle>
          <div style={{
            borderRadius: 'var(--radius)',
            background: 'var(--bg-card)',
            boxShadow: 'var(--shadow-sm)',
            overflow: 'hidden',
          }}>
            {companyInfo.map((row, i) => (
              <div key={row.label} style={{
                display: 'flex',
                padding: '12px 16px',
                borderBottom: i < companyInfo.length - 1 ? '0.5px solid var(--border)' : 'none',
                gap: 12,
              }}>
                <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-tertiary)', minWidth: 80, flexShrink: 0 }}>
                  {row.label}
                </div>
                <div style={{ fontSize: 13, color: 'var(--text-primary)', lineHeight: 1.5, whiteSpace: 'pre-line' }}>
                  {row.value}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Products & Services */}
        <section style={{ marginBottom: 24 }}>
          <SectionTitle>事業・サービス</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {products.map((p) => {
              const inner = (
                <div style={{
                  display: 'flex', alignItems: 'center', gap: 12,
                  padding: '12px 14px',
                  borderRadius: 'var(--radius-sm)',
                  background: 'var(--bg-card)',
                  boxShadow: 'var(--shadow-sm)',
                  border: '1px solid var(--border)',
                }}>
                  <span style={{ fontSize: 24 }}>{p.icon}</span>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)' }}>{p.title}</div>
                    <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginTop: 2 }}>{p.desc}</div>
                  </div>
                </div>
              );
              return p.internal ? (
                <Link key={p.title} to={p.url} style={{ textDecoration: 'none' }}>{inner}</Link>
              ) : (
                <a key={p.title} href={p.url} target="_blank" rel="noopener" style={{ textDecoration: 'none' }}>{inner}</a>
              );
            })}
          </div>
        </section>

        {/* Note about AICU Japan */}
        <section style={{ marginBottom: 24 }}>
          <div style={{
            padding: '14px 16px',
            borderRadius: 'var(--radius)',
            background: 'var(--bg-card)',
            boxShadow: 'var(--shadow-sm)',
            fontSize: 12,
            color: 'var(--text-secondary)',
            lineHeight: 1.7,
          }}>
            事業拡大に伴い、2024年11月11日に日本法人登記を申請いたしました。
            詳しくは<a href="https://corp.aicu.ai/ja/tag/aicu-japan" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)' }}>コーポレートブログ</a>にてお伝えしております。
            利用規約やプライバシーポリシーなどの日本法への遵法に関しましても整備を進めております。
          </div>
        </section>

        {/* Related links */}
        <section style={{ marginBottom: 24 }}>
          <SectionTitle>関連リンク</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {relatedLinks.map((link) => (
              <a
                key={link.url}
                href={link.url}
                target="_blank"
                rel="noopener"
                style={{
                  display: 'flex', alignItems: 'center', gap: 10,
                  padding: '12px 16px',
                  borderRadius: 'var(--radius-sm)',
                  background: 'var(--bg-card)',
                  boxShadow: 'var(--shadow-sm)',
                  textDecoration: 'none',
                  fontSize: 13,
                  fontWeight: 600,
                  color: 'var(--aicu-rose-dark)',
                }}
              >
                <span>{link.icon}</span>
                <span>{link.label}</span>
              </a>
            ))}
          </div>
        </section>

        <Footer />
      </main>
    </div>
  );
}

function SectionTitle({ children }) {
  return (
    <h2 style={{
      fontSize: 13, fontWeight: 700, color: 'var(--text-tertiary)',
      textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 12,
    }}>
      {children}
    </h2>
  );
}

const styles = {
  header: {
    position: 'sticky', top: 0, zIndex: 50,
    background: 'var(--bg-nav)',
    backdropFilter: 'blur(20px) saturate(180%)',
    WebkitBackdropFilter: 'blur(20px) saturate(180%)',
    borderBottom: '0.5px solid var(--border)',
  },
  headerInner: {
    maxWidth: 640, margin: '0 auto', padding: '14px 16px',
    display: 'flex', alignItems: 'center', gap: 10,
  },
  logo: {
    fontFamily: "'Outfit', sans-serif", fontSize: 18, fontWeight: 800,
    color: 'var(--aicu-rose)', letterSpacing: '-0.02em',
  },
  headerTitle: {
    fontSize: 15, fontWeight: 600, color: 'var(--text-primary)',
  },
};

