import AiCuty from './pages/AiCuty';
import Events from './pages/Events';
import EventArchive from './pages/EventArchive';
import './index.css';

function GtagRouteTracker() {
  const location = useLocation();
  useEffect(() => {
    if (window.gtag) {
      window.gtag('config', 'G-9Z2S3ZBGEV', { page_path: location.pathname });
    }
  }, [location]);
  return null;
}

export default function App() {
  return (
    <AuthProvider>
