  1→import { useState, useEffect, useCallback } from 'react';
  2→import { fetchRSS } from '../utils/rss';
  3→
  4→const FEEDS = {
  5→  aicu: {
  6→    url: 'https://note.com/aicu/rss',
  7→    staticUrl: '/data/feed-aicu.json',
  8→    name: 'AICU',
  9→    color: '#41C9B4',
 10→  },
 11→};
 12→
 13→const CACHE_KEY = 'aicu_feed_cache';
 14→const CACHE_TTL = 5 * 60 * 1000; // 5 minutes
 15→
 16→function getCache(feedKey) {
 17→  try {
 18→    const raw = localStorage.getItem(`${CACHE_KEY}_${feedKey}`);
 19→    if (!raw) return null;
 20→    const { data, timestamp } = JSON.parse(raw);
 21→    return { data, timestamp, fresh: Date.now() - timestamp < CACHE_TTL };
 22→  } catch {
 23→    return null;
 24→  }
 25→}
 26→
 27→function setCache(feedKey, data) {
 28→  try {
 29→    localStorage.setItem(`${CACHE_KEY}_${feedKey}`, JSON.stringify({
 30→      data,
 31→      timestamp: Date.now(),
 32→    }));
 33→  } catch { /* quota exceeded — ignore */ }
 34→}
 35→
 36→/** Fetch static JSON feed, parse date strings back to Date objects */
 37→async function fetchStaticFeed(url) {
 38→  const res = await fetch(url);
 39→  if (!res.ok) throw new Error(`Static feed ${res.status}`);
 40→  const json = await res.json();
 41→  // Support both { updatedAt, articles: [...] } and plain array
 42→  const raw = Array.isArray(json) ? json : json.articles || [];
 43→  const updatedAt = json.updatedAt || null;
 44→  const items = raw.map(item => ({
 45→    ...item,
 46→    pubDate: new Date(item.pubDate),
 47→  }));
 48→  return { items, updatedAt };
 49→}
 50→
 51→export function useFeed(feedKey = 'aicu') {
 52→  const [articles, setArticles] = useState(() => {
 53→    const cached = getCache(feedKey);
 54→    return cached ? cached.data : [];
 55→  });
 56→  const [loading, setLoading] = useState(() => {
 57→    return !getCache(feedKey);
 58→  });
 59→  const [error, setError] = useState(null);
 60→  const [refreshing, setRefreshing] = useState(false);
 61→  const [updatedAt, setUpdatedAt] = useState(null);
 62→
 63→  const load = useCallback(async (isRefresh = false) => {
 64→    if (isRefresh) setRefreshing(true);
 65→    else {
 66→      const cached = getCache(feedKey);
 67→      if (cached) {
 68→        setArticles(cached.data);
 69→        if (cached.fresh) {
 70→          setLoading(false);
 71→          return;
 72→        }
 73→      }
 74→      if (!cached) setLoading(true);
 75→    }
 76→    setError(null);
 77→
 78→    try {
 79→      const feed = FEEDS[feedKey];
 80→      if (!feed) throw new Error('Unknown feed');
 81→
 82→      let items;
 83→      // Try static JSON first (pre-cached by CI/cron), fall back to live RSS
 84→      if (feed.staticUrl) {
 85→        try {
 86→          const result = await fetchStaticFeed(feed.staticUrl);
 87→          items = result.items;
 88→          if (result.updatedAt) setUpdatedAt(result.updatedAt);
 89→        } catch {
 90→          items = await fetchRSS(feed.url);
 91→        }
 92→      } else {
 93→        items = await fetchRSS(feed.url);
 94→      }
 95→
 96→      setArticles(items);
 97→      setCache(feedKey, items);
 98→    } catch (e) {
 99→      if (!articles.length) setError(e.message);
100→    } finally {
101→      setLoading(false);
102→      setRefreshing(false);
103→    }
104→  }, [feedKey]);
105→
106→  useEffect(() => { load(); }, [load]);
107→
108→  return { articles, loading, error, refreshing, updatedAt, refresh: () => load(true) };
109→}
110→
111→export { FEEDS };
112→

 1→const CORS_PROXY = 'https://api.allorigins.win/raw?url=';
 2→
 3→export async function fetchRSS(url) {
 4→  try {
 5→    const res = await fetch(`${CORS_PROXY}${encodeURIComponent(url)}`);
 6→    if (!res.ok) throw new Error(`HTTP ${res.status}`);
 7→    const text = await res.text();
 8→    return parseRSS(text);
 9→  } catch (err) {
10→    console.error('RSS fetch error:', err);
11→    return [];
12→  }
13→}
14→
15→function parseRSS(xml) {
16→  const parser = new DOMParser();
17→  const doc = parser.parseFromString(xml, 'text/xml');
18→  const items = doc.querySelectorAll('item');
19→  
20→  return Array.from(items).map(item => {
21→    const title = item.querySelector('title')?.textContent || '';
22→    const link = item.querySelector('link')?.textContent || '';
23→    const pubDate = item.querySelector('pubDate')?.textContent || '';
24→    const description = item.querySelector('description')?.textContent || '';
25→    const guid = item.querySelector('guid')?.textContent || link;
26→    
27→    // Extract thumbnail from media:thumbnail or description img
28→    let thumbnail = '';
29→    const mediaThumbnail = item.querySelector('thumbnail');
30→    if (mediaThumbnail) {
31→      thumbnail = mediaThumbnail.getAttribute('url') || mediaThumbnail.textContent || '';
32→    }
33→    if (!thumbnail) {
34→      const imgMatch = description.match(/<img[^>]+src="([^"]+)"/);
35→      if (imgMatch) thumbnail = imgMatch[1];
36→    }
37→
38→    // Extract creator name
39→    const creatorName = item.querySelector('creatorName')?.textContent || 'AICU';
40→
41→    // Strip HTML and truncate description for preview
42→    const plainDesc = description
43→      .replace(/<!\[CDATA\[|\]\]>/g, '')
44→      .replace(/<[^>]+>/g, '')
45→      .replace(/続きをみる$/,'')
46→      .trim()
47→      .slice(0, 200);
48→
49→    return {
50→      id: guid,
51→      title,
52→      link,
53→      pubDate: new Date(pubDate),
54→      description: plainDesc,
55→      thumbnail,
56→      creator: creatorName,
57→    };
58→  });
59→}
60→
61→export function formatDate(date) {
62→  if (typeof date === 'string') date = new Date(date);
63→  if (!(date instanceof Date) || isNaN(date)) return '';
64→  const now = new Date();
65→  const diff = now - date;
66→  const hours = diff / (1000 * 60 * 60);
67→  
68→  if (hours < 1) return `${Math.floor(diff / 60000)}分前`;
69→  if (hours < 24) return `${Math.floor(hours)}時間前`;
70→  if (hours < 48) return '昨日';
71→  if (hours < 168) return `${Math.floor(hours / 24)}日前`;
72→  
73→  return `${date.getMonth() + 1}/${date.getDate()}`;
74→}
