  9→ * R2 layout:
 10→ *   note/YYMMDD.png       — thumbnail images
 11→ *   data/feed-aicu.json   — feed JSON (served by Pages Function)
 12→ *   meta/rss-hash.txt     — MD5 of last processed RSS
 13→ */
 14→
 15→const RSS_URL = 'https://note.com/aicu/rss';
 16→
 17→// ---------------------------------------------------------------------------
 18→// Crypto helpers (Web Crypto API)
 19→// ---------------------------------------------------------------------------
 20→async function md5Hex(text) {
 21→  const data = new TextEncoder().encode(text);
 22→  const hash = await crypto.subtle.digest('MD5', data);
 23→  return [...new Uint8Array(hash)].map(b => b.toString(16).padStart(2, '0')).join('');
 24→}
 25→
 26→// ---------------------------------------------------------------------------
 27→// Date helpers
 28→// ---------------------------------------------------------------------------
 29→function dateToYYMMDD(isoDate) {
 30→  const d = new Date(isoDate);
 31→  const jst = new Date(d.getTime() + 9 * 60 * 60 * 1000);
 32→  const yy = String(jst.getUTCFullYear()).slice(-2);
 33→  const mm = String(jst.getUTCMonth() + 1).padStart(2, '0');
 34→  const dd = String(jst.getUTCDate()).padStart(2, '0');
 35→  return `${yy}${mm}${dd}`;
 36→}
 37→
 38→function extFromUrl(url) {
 39→  try {
 40→    const pathname = new URL(url).pathname;
 41→    const ext = pathname.split('.').pop().toLowerCase();
 42→    if (['png', 'jpg', 'jpeg', 'webp', 'gif'].includes(ext)) return ext;
 43→  } catch {}
 44→  return 'png';
 45→}
 46→
 47→// ---------------------------------------------------------------------------
 48→// Minimal XML parser (no dependencies, handles note.com RSS)
 49→// ---------------------------------------------------------------------------
 50→function parseRSS(xml) {
 51→  const items = [];
 52→  const itemRegex = /<item>([\s\S]*?)<\/item>/g;
 53→  let match;
 54→
 55→  while ((match = itemRegex.exec(xml)) !== null) {
 56→    const block = match[1];
 57→    const get = (tag) => {
 58→      const m = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`));
 59→      return m ? m[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').trim() : '';
 60→    };
 61→
 62→    const title = get('title');
 63→    const link = get('link');
 64→    const guid = get('guid') || link;
 65→    const pubDateRaw = get('pubDate');
 66→    const pubDate = pubDateRaw ? new Date(pubDateRaw).toISOString() : '';
 67→    const rawDesc = get('description');
 68→    const creator = get('note:creatorName') || 'AICU';
 69→
 70→    // media:thumbnail — note.com puts URL as text content
 71→    let thumbnail = '';
 72→    const thumbMatch = block.match(/<media:thumbnail[^>]*>([^<]+)<\/media:thumbnail>/);
 73→    if (thumbMatch) {
 74→      thumbnail = thumbMatch[1].trim();
 75→    } else {
 76→      // Try url attribute fallback
 77→      const attrMatch = block.match(/<media:thumbnail[^>]+url="([^"]+)"/);
 78→      if (attrMatch) thumbnail = attrMatch[1].trim();
 79→    }
 80→
 81→    // Strip HTML from description
 82→    const plainDesc = rawDesc
 83→      .replace(/<[^>]+>/g, '')
 84→      .replace(/&amp;/g, '&')
 85→      .replace(/&lt;/g, '<')
 86→      .replace(/&gt;/g, '>')
 87→      .replace(/&quot;/g, '"')
 88→      .replace(/&#39;/g, "'")
 89→      .replace(/続きをみる$/, '')
 90→      .trim()
 91→      .slice(0, 200);
 92→
 93→    items.push({ id: guid, title, link, pubDate, description: plainDesc, thumbnail, creator });
 94→  }
 95→
 96→  return items;
 97→}
 98→
 99→// ---------------------------------------------------------------------------
100→// R2 helpers
101→// ---------------------------------------------------------------------------
102→async function r2GetText(bucket, key) {
103→  const obj = await bucket.get(key);
104→  if (!obj) return null;
105→  return obj.text();
106→}
107→
108→async function r2Exists(bucket, key) {
109→  const head = await bucket.head(key);
110→  return head !== null;
111→}
112→
113→const CONTENT_TYPES = {
114→  png: 'image/png', jpg: 'image/jpeg', jpeg: 'image/jpeg',
115→  webp: 'image/webp', gif: 'image/gif',
116→};
117→
118→async function uploadThumbnail(bucket, imageUrl, yymmdd) {
119→  const ext = extFromUrl(imageUrl);
120→  const key = `note/${yymmdd}.${ext}`;
121→
122→  if (await r2Exists(bucket, key)) {
123→    return `/img/note/${yymmdd}.${ext}`;
124→  }
125→
126→  const res = await fetch(imageUrl);
127→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
128→  const body = await res.arrayBuffer();
129→
130→  await bucket.put(key, body, {
131→    httpMetadata: {
132→      contentType: CONTENT_TYPES[ext] || 'application/octet-stream',
133→      cacheControl: 'public, max-age=31536000, immutable',
134→    },
135→  });
136→
137→  return `/img/note/${yymmdd}.${ext}`;
138→}
139→
140→// ---------------------------------------------------------------------------
141→// Main logic
142→// ---------------------------------------------------------------------------
143→async function updateFeed(env) {
144→  const bucket = env.MEDIA;
145→
146→  // 1. Fetch RSS
147→  const rssRes = await fetch(RSS_URL);
148→  if (!rssRes.ok) throw new Error(`RSS fetch failed: ${rssRes.status}`);
149→  const rssXml = await rssRes.text();
150→
151→  // 2. Hash check
152→  const newHash = await md5Hex(rssXml);
153→  const oldHash = await r2GetText(bucket, 'meta/rss-hash.txt');
154→
155→  if (newHash === oldHash) {
156→    console.log('No changes detected (hash match). Skipping.');
157→    return { updated: false, hash: newHash };
158→  }
159→  console.log(`Change detected! old=${oldHash || '(none)'} new=${newHash}`);
160→
161→  // 3. Parse
162→  const items = parseRSS(rssXml);
163→  console.log(`Parsed ${items.length} articles`);
164→
165→  // 4. Assign YYMMDD names
166→  const dateCount = {};
167→  for (const item of items) {
168→    if (!item.pubDate) continue;
169→    const base = dateToYYMMDD(item.pubDate);
170→    dateCount[base] = (dateCount[base] || 0) + 1;
171→    item._yymmdd = dateCount[base] === 1 ? base : `${base}-${dateCount[base]}`;
172→  }
173→
174→  // 5. Upload thumbnails
175→  let uploaded = 0;
176→  for (const item of items) {
177→    if (!item.thumbnail || !item._yymmdd) continue;
178→    try {
179→      const oldUrl = item.thumbnail;
180→      item.thumbnail = await uploadThumbnail(bucket, oldUrl, item._yymmdd);
181→      uploaded++;
182→    } catch (err) {
183→      console.error(`Failed: ${item._yymmdd} — ${err.message}`);
184→      // Keep original URL
185→    }
186→  }
187→  console.log(`Thumbnails processed: ${uploaded}/${items.length}`);
188→
189→  // 6. Write feed JSON to R2
190→  const output = items.map(({ _yymmdd, ...rest }) => rest);
191→  const feed = { updatedAt: new Date().toISOString(), articles: output };
192→  await bucket.put('data/feed-aicu.json', JSON.stringify(feed, null, 2), {
193→    httpMetadata: {
194→      contentType: 'application/json',
195→      cacheControl: 'public, max-age=300',
196→    },
197→  });
198→
199→  // 7. Save hash
200→  await bucket.put('meta/rss-hash.txt', newHash, {
201→    httpMetadata: { contentType: 'text/plain' },
202→  });
203→
204→  console.log('Feed updated successfully.');
205→  return { updated: true, hash: newHash, articles: items.length, uploaded };
206→}
207→
208→// ---------------------------------------------------------------------------
209→// Daily push notification (12:00 JST = 03:00 UTC)
210→// ---------------------------------------------------------------------------
211→async function sendDailyPush(env) {
212→  const bucket = env.MEDIA;
213→  const apiUrl = env.PUSH_API_URL;
214→  const apiKey = env.CRON_API_KEY;
215→
216→  if (!apiUrl || !apiKey) {
217→    console.log('PUSH_API_URL or CRON_API_KEY not configured. Skipping push.');
218→    return { pushed: false, reason: 'not configured' };
219→  }
220→
221→  // Read latest feed from R2
222→  const feedObj = await bucket.get('data/feed-aicu.json');
223→  if (!feedObj) {
224→    console.log('No feed JSON in R2. Skipping push.');
225→    return { pushed: false, reason: 'no feed' };
226→  }
227→
228→  const feed = JSON.parse(await feedObj.text());
229→  const articles = feed.articles || [];
230→  if (articles.length === 0) {
231→    return { pushed: false, reason: 'no articles' };
232→  }
233→
234→  const a1 = articles[0];
235→  const a2 = articles.length > 1 ? articles[1] : null;
236→  const title = a1.title;
237→  const body = a2 ? `${a1.title}／${a2.title}` : a1.title;
238→  const url = 'https://aicu.jp/news';
239→
240→  const res = await fetch(apiUrl, {
241→    method: 'POST',
242→    headers: {
243→      'Content-Type': 'application/json',
244→      'X-Cron-Key': apiKey,
245→    },
246→    body: JSON.stringify({ title, body, url }),
247→  });
248→
249→  const result = await res.json();
250→  console.log(`Push notification sent: ${JSON.stringify(result)}`);
251→  return { pushed: true, ...result };
252→}
253→
254→// ---------------------------------------------------------------------------
255→// Worker entry
256→// ---------------------------------------------------------------------------
257→export default {
258→  // Cron trigger
259→  async scheduled(event, env, ctx) {
260→    // Always update feed
261→    ctx.waitUntil(updateFeed(env));
262→
263→    // Daily push at 02:55 UTC (11:55 JST)
264→    const t = new Date(event.scheduledTime);
265→    if (t.getUTCHours() === 2 && t.getUTCMinutes() === 55) {
266→      ctx.waitUntil(sendDailyPush(env));
267→    }
268→  },
269→
270→  // HTTP trigger (manual / debug)
271→  async fetch(request, env) {
272→    const url = new URL(request.url);
273→
274→    // POST /push — manual push trigger
275→    if (request.method === 'POST' && url.pathname === '/push') {
276→      try {
277→        const result = await sendDailyPush(env);
278→        return Response.json(result);
279→      } catch (err) {
280→        return Response.json({ error: err.message }, { status: 500 });
281→      }
282→    }
283→
284→    // POST — feed update trigger
285→    if (request.method === 'POST') {
286→      try {
287→        const result = await updateFeed(env);
288→        return Response.json(result);
289→      } catch (err) {
290→        return Response.json({ error: err.message }, { status: 500 });
291→      }
292→    }
293→
294→    return new Response('POST to trigger feed update. POST /push to trigger daily notification.', { status: 200 });
295→  },
296→};
297→

