                href={ch.url}
                target="_blank"
                rel="noopener"
                style={{
                  display: 'flex', alignItems: 'flex-start', gap: 12,
                  padding: '14px 16px',
                  borderRadius: 'var(--radius)',
                  background: 'var(--bg-card)',
                  boxShadow: 'var(--shadow-sm)',
                  border: '1px solid var(--border)',
