            AIツール開発者、デジタルコンテンツ制作者、AI DX 推進担当者、
            教育機関・研究者。生成AI利用実態調査「R2602」の調査パネルとも連動。
          </div>
        </section>

        {/* Press info */}
        <section style={{ marginBottom: 28 }}>
          <SectionTitle>プレス向け情報</SectionTitle>
          <div style={{
            borderRadius: 'var(--radius)',
            background: 'var(--bg-card)',
            boxShadow: 'var(--shadow-sm)',
            overflow: 'hidden',
          }}>
            {pressInfo.map((row, i) => (
              <div key={row.label} style={{
                display: 'flex',
                padding: '12px 16px',
                borderBottom: i < pressInfo.length - 1 ? '0.5px solid var(--border)' : 'none',
                gap: 12,
              }}>
                <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-tertiary)', minWidth: 72, flexShrink: 0 }}>
                  {row.label}
                </div>
                <div style={{ fontSize: 13, color: 'var(--text-primary)', lineHeight: 1.5, whiteSpace: 'pre-line', wordBreak: 'break-all' }}>
                  {row.value}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Contact CTA */}
        <section style={{ marginBottom: 28, textAlign: 'center' }}>
          <a
            href="https://www.aicu.blog/contact"
            target="_blank"
            rel="noopener"
            style={{
              display: 'inline-block',
              padding: '12px 28px',
              borderRadius: 'var(--radius)',
              background: 'var(--aicu-rose)',
              color: '#fff',
              fontSize: 14,
              fontWeight: 700,
              textDecoration: 'none',
              boxShadow: 'var(--shadow-sm)',
            }}
          >
            お問い合わせ
          </a>
        </section>

        <Footer />
      </main>
    </div>
  );
}

function SectionTitle({ children }) {
  return (
    <h2 style={{
      fontSize: 13, fontWeight: 700, color: 'var(--text-tertiary)',
      textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 12,
    }}>
      {children}
    </h2>
  );
}

const styles = {
  header: {
    position: 'sticky', top: 0, zIndex: 50,
    background: 'var(--bg-nav)',
    backdropFilter: 'blur(20px) saturate(180%)',
    WebkitBackdropFilter: 'blur(20px) saturate(180%)',
