import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import { VitePWA } from 'vite-plugin-pwa'
import sitemap from 'vite-plugin-sitemap'
import fs from 'node:fs'
import path from 'node:path'

// Serve public/e/**/index.html as-is (bypass SPA fallback)
function staticEventsPlugin() {
  return {
    name: 'static-events',
    configureServer(server) {
      server.middlewares.use((req, res, next) => {
        if (req.url?.startsWith('/e/') && !path.extname(req.url)) {
          const tryPath = path.join('public', req.url.replace(/\/$/, ''), 'index.html')
          if (fs.existsSync(tryPath)) {
            req.url = req.url.replace(/\/?$/, '/index.html')
          }
        }
        next()
      })
    },
  }
}

// https://vite.dev/config/
export default defineConfig({
  plugins: [
    staticEventsPlugin(),
    react(),
    sitemap({
      hostname: 'https://aicu.jp',
      dynamicRoutes: ['/media', '/search', '/about', '/create/voice', '/aicuty', '/e', '/corp'],
      readable: true,
    }),
    VitePWA({
      registerType: 'autoUpdate',
      includeAssets: ['icon-192.png', 'icon-512.png'],
      manifest: {
        name: 'AICU',
        short_name: 'AICU',
        description: '生成AI時代に「つくる人をつくる」',
        theme_color: '#fe59a1',
        background_color: '#fff0f5',
        display: 'standalone',
        start_url: '/',
        icons: [
          { src: '/icon-192.png', sizes: '192x192', type: 'image/png' },
          { src: '/icon-512.png', sizes: '512x512', type: 'image/png' },
        ],
      },
      workbox: {
        // Import custom SW for push event handling
        importScripts: ['/sw-push.js'],
        skipWaiting: true,
        clientsClaim: true,
        navigateFallbackDenylist: [/^\/e\/Fes26Halu/],
      },
    }),
  ],
  server: {
    port: 3150,
  },
})

