import { Link } from 'react-router-dom';
import FeedCarousel from '../components/FeedCarousel';
import Footer from '../components/Footer';
import usePageMeta from '../hooks/usePageMeta';

export default function Service() {
  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={{
        position: 'sticky',
        top: 0,
        zIndex: 50,
        background: 'var(--bg-nav)',
        backdropFilter: 'blur(20px) saturate(180%)',
        WebkitBackdropFilter: 'blur(20px) saturate(180%)',
        borderBottom: '0.5px solid var(--border)',
      }}>
        <div style={{
          maxWidth: 640,
          margin: '0 auto',
          padding: '14px 16px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: 10,
        }}>
          {/* Brand + tagline */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 10, flexShrink: 0 }}>
            <span style={{
              fontFamily: "'Outfit', sans-serif",
              fontSize: 22,
              fontWeight: 800,
              color: 'var(--aicu-rose)',
              letterSpacing: '-0.02em',
            }}>
              AICU Japan
            </span>
            <span style={{
              fontSize: 10,
              color: 'var(--text-tertiary)',
              lineHeight: 1.3,
              marginLeft: 2,
            }}>
              クリエイティブAI時代に<br />つくる人をつくる
            </span>
          </div>

          {/* Announcement pill */}
          {announcement && (
            <a
              href={announcement.url}
              target="_blank"
              rel="noopener noreferrer"
              style={{
                display: 'flex',
                flexDirection: 'column',
                gap: 2,
                padding: '6px 10px',
                borderRadius: 10,
                background: 'linear-gradient(135deg, rgba(65,201,180,0.08), rgba(108,99,255,0.08))',
                border: '1px solid rgba(65,201,180,0.2)',
                textDecoration: 'none',
                minWidth: 0,
                maxWidth: 200,
                transition: 'border-color 0.15s',
              }}
            >
              <span style={{
                fontSize: 8,
                fontWeight: 700,
                color: 'var(--aicu-rose)',
                letterSpacing: '0.08em',
                textTransform: 'uppercase',
              }}>
                {announcement.label}
              </span>
              <span style={{
                fontSize: 10,
                fontWeight: 600,
                color: 'var(--text-primary)',
                lineHeight: 1.3,
                display: '-webkit-box',
                WebkitLineClamp: 2,
                WebkitBoxOrient: 'vertical',
                overflow: 'hidden',
              }}>
                {announcement.title}
              </span>
            </a>
          )}
        </div>
      </header>

      <main style={{
        maxWidth: 640,
        margin: '0 auto',
        padding: 16,
      }}>
        {/* Hero Banner — R2602 Survey */}
        <a href="https://p.aicu.jp/R2602?utm_source=aicujp&utm_medium=website&utm_campaign=r2602" style={{ display: 'block', marginBottom: 16, textDecoration: 'none' }}>
          <div style={{
            position: 'relative',
            borderRadius: 'var(--radius)',
            overflow: 'hidden',
          }}>
            <img
              src="/r2602-banner.png"
              alt="生成AI時代の「つくる人」調査 R2602"
              width={640}
              height={357}
              style={{
                width: '100%',
                height: 'auto',
                display: 'block',
                borderRadius: 'var(--radius)',
              }}
            />
            <div style={{
              position: 'absolute',
              bottom: 0,
              left: 0,
              right: 0,
              padding: '24px 14px 10px',
              background: 'linear-gradient(transparent, rgba(0,0,0,0.7))',
              borderRadius: '0 0 var(--radius) var(--radius)',
            }}>
              <div style={{
                display: 'inline-block',
                padding: '3px 10px',
                borderRadius: 12,
                background: 'linear-gradient(135deg, #41C9B4, #6C63FF)',
