        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(2, 1fr)',
          gap: 10,
          marginBottom: 20,
        }}>
          {mainCards.map((card) =>
            card.internal ? (
              <Link
                key={card.label}
                to={card.url}
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 6,
                  padding: '18px 14px',
                  borderRadius: 'var(--radius)',
                  background: `linear-gradient(135deg, var(--aicu-rose-light), var(--bg-card))`,
                  border: '1px solid var(--aicu-rose)',
                  textDecoration: 'none',
                  boxShadow: 'var(--shadow-sm)',
                  transition: 'transform 0.15s',
                }}
              >
                <span style={{ fontSize: 28 }}>{card.icon}</span>
                <span style={{
                  fontSize: 14,
                  fontWeight: 700,
