                <span style={{
                  fontSize: 11,
                  color: 'var(--text-secondary)',
                  lineHeight: 1.4,
                }}>
                  {card.label}
                </span>
              </Link>
            ) : (
              <a
                key={card.label}
                href={card.url}
                target="_blank"
                rel="noopener"
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 6,
                  padding: '18px 14px',
                  borderRadius: 'var(--radius)',
                  background: `linear-gradient(135deg, var(--aicu-rose-light), var(--bg-card))`,
                  border: '1px solid var(--aicu-rose)',
                  textDecoration: 'none',
                  boxShadow: 'var(--shadow-sm)',
                  transition: 'transform 0.15s',
                }}
              >
                <span style={{ fontSize: 28 }}>{card.icon}</span>
                <span style={{
                  fontSize: 14,
                  fontWeight: 700,
                  color: 'var(--aicu-rose-dark)',
                  fontFamily: "'Outfit', sans-serif",
                }}>
                  {card.name}
                </span>
                <span style={{
                  fontSize: 11,
                  color: 'var(--text-secondary)',
                  lineHeight: 1.4,
                }}>
                  {card.label}
                </span>
              </a>
            )
          )}
        </div>

        {/* Service Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(3, 1fr)',
          gap: 10,
        }}>
          {serviceLinks.map((s) => {
            const inner = (
              <>
                <span style={{ fontSize: 28 }}>{s.icon}</span>
                <span style={{
                  fontSize: 11,
                  fontWeight: 600,
                  color: 'var(--text-secondary)',
                  textAlign: 'center',
                  lineHeight: 1.3,
                  wordBreak: 'keep-all',
                }}>
                  {s.label}
                </span>
              </>
            );
            const cardStyle = {
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: 8,
              padding: '16px 8px',
              borderRadius: 14,
              background: 'var(--bg-card)',
              textDecoration: 'none',
              boxShadow: '0 1px 6px rgba(0,0,0,0.04)',
              transition: 'transform 0.15s',
            };
            return s.internal ? (
              <Link key={s.label} to={s.url} style={cardStyle}>
                {inner}
              </Link>
            ) : (
              <a key={s.label} href={s.url} target="_blank" rel="noopener" style={cardStyle}>
                {inner}
              </a>
            );
          })}
        </div>

        {/* Footer Links */}
        <footer style={{
          padding: '28px 0 16px',
          textAlign: 'center',
          fontSize: 11,
          color: 'var(--text-tertiary)',
        }}>
          <div style={{
            display: 'flex',
            flexWrap: 'wrap',
            justifyContent: 'center',
            gap: '4px 14px',
            marginBottom: 14,
          }}>
            {footerLinks.map((f) => (
              <a
                key={f.label}
                href={f.url}
                target="_blank"
                rel="noopener"
                style={{ color: 'var(--text-tertiary)', textDecoration: 'none' }}
              >
                {f.label}
              </a>
            ))}
          </div>
          <p>
            Powered by{' '}
            <a href="https://aicu.jp" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>AICU Japan</a>
            {' / '}
            <a href="https://x.com/aicuai" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>X@AICUai</a>
            {' / '}
            <Link to="/corp" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>AboutUs</Link>
          </p>
        </footer>
      </main>
    </div>
  );
}

