toolUseResult.originalFile:
import { useEffect } from 'react';
import { Link } from 'react-router-dom';
import { characters } from '../data/characters';
import { events } from '../data/events';
import Footer from '../components/Footer';
import usePageMeta from '../hooks/usePageMeta';

const jsonLd = {
  '@context': 'https://schema.org',
  '@type': 'CreativeWork',
  name: 'AiCuty — AI×クリエイティブ アイドルユニット',
  description: 'AICU が生んだ5人組バーチャルアイドル。LLM・画像・音楽・動画・倫理、それぞれの専門分野を持つメンバーが AI クリエイティブの未来を拓く。',
  url: 'https://aicu.jp/aicuty',
  image: 'https://aicu.jp/CoverArtWithText.webp',
  creator: { '@type': 'Organization', name: 'AICU Japan株式会社', url: 'https://aicu.jp' },
};

const aicutyEvents = events.filter((e) => e.tags.includes('aicuty') || e.tags.includes('voice'));

const statusLabel = { live: 'LIVE', preview: 'Coming soon', archive: 'Archive' };
const statusColor = {
  live: { bg: '#dcfce7', text: '#166534' },
  preview: { bg: '#fef9c3', text: '#854d0e' },
  archive: { bg: 'var(--bg-card)', text: 'var(--text-tertiary)' },
};

export default function AiCuty() {
  useEffect(() => {
    const script = document.createElement('script');
    script.type = 'application/ld+json';
    script.textContent = JSON.stringify(jsonLd);
    document.head.appendChild(script);
    return () => script.remove();
  }, []);

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>← AICU</span>
          </Link>
          <span style={styles.headerTitle}>AiCuty</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '0 16px 40px' }}>
        {/* Hero */}
        <section style={{ textAlign: 'center', padding: '20px 0 16px' }}>
          <img
            src="/CoverArtWithText.webp"
            alt="AiCuty メンバー"
            width={640}
            height={357}
            style={{
              width: '100%',
              height: 'auto',
              borderRadius: 'var(--radius)',
              boxShadow: 'var(--shadow-sm)',
              marginBottom: 14,
            }}
          />
          <h1 style={{ fontSize: 22, fontWeight: 800, color: 'var(--text-primary)', lineHeight: 1.4 }}>
            AI×クリエイティブ アイドルユニット
          </h1>
          <p style={{ fontSize: 13, color: 'var(--text-secondary)', marginTop: 6, lineHeight: 1.6 }}>
            LLM・画像・音楽・動画・倫理 — 5つの専門分野を持つバーチャルアイドルが、AI クリエイティブの未来を拓く。
          </p>
        </section>

        {/* Members */}
        <section style={{ marginBottom: 28 }}>
          <SectionTitle>Members</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {characters.map((char) => (
              <div
                key={char.id}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 12,
                  padding: '14px 14px',
                  borderRadius: 'var(--radius)',
                  background: `linear-gradient(135deg, ${char.color}12, var(--bg-card))`,
                  border: `1px solid ${char.color}40`,
                  boxShadow: 'var(--shadow-sm)',
                }}
              >
                <img
                  src={`/characters/${char.id}.webp`}
                  alt={char.name}
                  style={{
                    width: 52,
                    height: 52,
                    borderRadius: '50%',
                    objectFit: 'cover',
                    border: `2.5px solid ${char.color}`,
                    flexShrink: 0,
                  }}
                />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
                    <span style={{ fontSize: 15, fontWeight: 700, color: char.color }}>
                      {char.emoji} {char.name}
                    </span>
                    <span style={{ fontSize: 11, color: 'var(--text-tertiary)' }}>
                      {char.nameJp}
                    </span>
                  </div>
                  <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginTop: 3 }}>
                    {char.personality}
                  </div>
                  <div style={{ fontSize: 10, color: 'var(--text-tertiary)', marginTop: 2 }}>
                    🎂 {char.birthday}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Related Events */}
        {aicutyEvents.length > 0 && (
          <section style={{ marginBottom: 28 }}>
            <SectionTitle>Events</SectionTitle>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {aicutyEvents.map((ev) => {
                const sc = statusColor[ev.status];
                const isLive = ev.status === 'live';
                const Wrapper = isLive ? 'a' : Link;
                const wrapperProps = isLive
                  ? { href: ev.staticPath, style: linkCardStyle }
                  : { to: `/e/${ev.shortcode}`, style: linkCardStyle };

                return (
                  <Wrapper key={ev.shortcode} {...wrapperProps}>
                    <span style={{ fontSize: 24 }}>{ev.emoji}</span>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                        <span style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)' }}>
                          {ev.title}
                        </span>
                        <span style={{
                          padding: '1px 6px',
                          borderRadius: 6,
                          fontSize: 9,
                          fontWeight: 700,
                          background: sc.bg,
                          color: sc.text,
                          border: ev.status === 'archive' ? '1px solid var(--border)' : 'none',
                        }}>
                          {statusLabel[ev.status]}
                        </span>
                      </div>
                      <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginTop: 2 }}>
                        {ev.description}
                      </div>
                    </div>
                  </Wrapper>
                );
              })}
            </div>
          </section>
        )}

        {/* Guideline */}
        <section style={{ marginBottom: 28 }}>
          <SectionTitle>Guideline</SectionTitle>
          <a
            href="https://www.aicu.jp/terms/aicuty-guideline"
            target="_blank"
            rel="noopener"
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 10,
              padding: '14px 16px',
              borderRadius: 'var(--radius)',
              background: 'var(--bg-card)',
              boxShadow: 'var(--shadow-sm)',
              textDecoration: 'none',
              fontSize: 13,
              fontWeight: 600,
              color: 'var(--aicu-rose-dark)',
            }}
          >
            <span>📚</span>
            <span>AiCuty 著作物利用ガイドライン</span>
          </a>
        </section>

        <Footer />
      </main>
    </div>
  );
}

function SectionTitle({ children }) {
  return (
    <h2 style={{
      fontSize: 13,
      fontWeight: 700,
      color: 'var(--text-tertiary)',
      textTransform: 'uppercase',
      letterSpacing: '0.06em',
      marginBottom: 12,
    }}>
      {children}
    </h2>
  );
}

const linkCardStyle = {
  display: 'flex',
  alignItems: 'center',
  gap: 10,
  padding: '12px 14px',
  borderRadius: 'var(--radius-sm)',
  background: 'var(--bg-card)',
  boxShadow: 'var(--shadow-sm)',
  textDecoration: 'none',
};

const styles = {
  header: {
    position: 'sticky',
    top: 0,
    zIndex: 50,
    background: 'var(--bg-nav)',
    backdropFilter: 'blur(20px) saturate(180%)',
    WebkitBackdropFilter: 'blur(20px) saturate(180%)',
    borderBottom: '0.5px solid var(--border)',
  },
  headerInner: {
    maxWidth: 640,
    margin: '0 auto',
    padding: '14px 16px',
    display: 'flex',
    alignItems: 'center',
    gap: 10,
  },
  logo: {
    fontFamily: "'Outfit', sans-serif",
    fontSize: 18,
    fontWeight: 800,
    color: 'var(--aicu-rose)',
    letterSpacing: '-0.02em',
  },
  headerTitle: {
    fontSize: 15,
    fontWeight: 600,
    color: 'var(--text-primary)',
  },
};

