import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { useNavigate } from 'react-router-dom';

const STEPS = { EMAIL: 'email', SENT: 'sent' };

export default function Login() {
  const { sendOtp, signInWithDiscord, signInWithGoogle, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(STEPS.EMAIL);
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [sending, setSending] = useState(false);

  useEffect(() => {
    if (isAuthenticated) navigate('/', { replace: true });
  }, [isAuthenticated, navigate]);

  const handleSendLink = async (e) => {
    e.preventDefault();
    if (!email.trim()) return;
    setError('');
    setSending(true);
    try {
      await sendOtp(email.trim());
      setStep(STEPS.SENT);
    } catch (err) {
      setError(err.message || 'メール送信に失敗しました');
    }
    setSending(false);
  };

  const handleResend = async () => {
    setError('');
    setSending(true);
    try {
      await sendOtp(email);
      setError('');
    } catch {
      setError('再送信に失敗しました');
    }
    setSending(false);
  };

  return (
    <div style={styles.container}>
      <div style={styles.inner}>
        {/* Logo */}
        <div style={styles.logoArea}>
          <span style={styles.logo}>AICU</span>
          <p style={styles.subtitle}>生成AI時代に「つくる人をつくる」</p>
        </div>

        {/* Email Step */}
        {step === STEPS.EMAIL && (
          <form onSubmit={handleSendLink} style={styles.form}>
