  1→import { useState, useEffect, useCallback } from 'react';
  2→import { useAuth } from '../hooks/useAuth';
  3→import { useArticleActions } from '../hooks/useArticleActions';
  4→import { useNavigate, Link } from 'react-router-dom';
  5→import { supabase } from '../utils/supabase';
  6→
  7→const VAPID_PUBLIC_KEY = import.meta.env.VITE_VAPID_PUBLIC_KEY;
  8→const P_AICUJP_ORIGIN = import.meta.env.DEV ? 'http://localhost:3200' : 'https://p.aicu.jp';
  9→
 10→export default function Profile() {
 11→  const { user, signOut, isAuthenticated } = useAuth();
 12→  const { bookmarkCount } = useArticleActions();
 13→  const navigate = useNavigate();
 14→
 15→  const [pushEnabled, setPushEnabled] = useState(false);
 16→  const [pushLoading, setPushLoading] = useState(false);
 17→  const [pushSupported] = useState(
 18→    () => 'serviceWorker' in navigator && 'PushManager' in window && !!VAPID_PUBLIC_KEY
 19→  );
 20→
 21→  // Display name editing
 22→  const [displayName, setDisplayName] = useState('');
 23→  const [displayNameSaved, setDisplayNameSaved] = useState(false);
 24→  const [displayNameLoading, setDisplayNameLoading] = useState(false);
 25→
 26→  useEffect(() => {
 27→    if (!user) return;
 28→    supabase
 29→      .from('profiles')
 30→      .select('display_name')
 31→      .eq('id', user.id)
 32→      .single()
 33→      .then(({ data }) => {
 34→        if (data?.display_name) setDisplayName(data.display_name);
 35→      });
 36→  }, [user]);
 37→
 38→  const handleSaveDisplayName = useCallback(async () => {
 39→    if (displayNameLoading || !user) return;
 40→    setDisplayNameLoading(true);
 41→    setDisplayNameSaved(false);
 42→    try {
 43→      await supabase
 44→        .from('profiles')
 45→        .upsert({ id: user.id, display_name: displayName.trim() || null }, { onConflict: 'id' });
 46→      setDisplayNameSaved(true);
 47→      setTimeout(() => setDisplayNameSaved(false), 2000);
 48→    } catch (err) {
 49→      console.error('Failed to save display_name:', err);
 50→    } finally {
 51→      setDisplayNameLoading(false);
 52→    }
 53→  }, [displayName, displayNameLoading, user]);
 54→  // iOS Safari: push only works in standalone (A2HS) mode
 55→  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent);
 56→  const isStandalone = window.matchMedia('(display-mode: standalone)').matches || navigator.standalone;
 57→  const isIOSBrowser = isIOS && !isStandalone;
 58→
 59→  // Check current push subscription state on mount
 60→  useEffect(() => {
 61→    if (!pushSupported || !isAuthenticated) return;
 62→    navigator.serviceWorker.ready.then((reg) => {
 63→      reg.pushManager.getSubscription().then((sub) => {
 64→        setPushEnabled(!!sub);
 65→      });
 66→    });
 67→  }, [pushSupported, isAuthenticated]);
 68→
 69→  const handlePushToggle = useCallback(async () => {
 70→    if (pushLoading) return;
 71→    setPushLoading(true);
 72→    try {
 73→      const reg = await navigator.serviceWorker.ready;
 74→      if (pushEnabled) {
 75→        // Unsubscribe
 76→        const sub = await reg.pushManager.getSubscription();
 77→        if (sub) {
 78→          const { data: { session } } = await supabase.auth.getSession();
 79→          await fetch(`${P_AICUJP_ORIGIN}/api/push/unsubscribe`, {
 80→            method: 'POST',
 81→            headers: {
 82→              'Content-Type': 'application/json',
 83→              'Authorization': `Bearer ${session?.access_token}`,
 84→            },
 85→            body: JSON.stringify({ endpoint: sub.endpoint }),
 86→          });
 87→          await sub.unsubscribe();
 88→        }
 89→        setPushEnabled(false);
 90→      } else {
 91→        // Subscribe
 92→        const permission = await Notification.requestPermission();
 93→        if (permission !== 'granted') {
 94→          setPushLoading(false);
 95→          return;
 96→        }
 97→        const sub = await reg.pushManager.subscribe({
 98→          userVisibleOnly: true,
 99→          applicationServerKey: VAPID_PUBLIC_KEY,
100→        });
101→        const key = sub.getKey('p256dh');
102→        const auth = sub.getKey('auth');
103→        const { data: { session } } = await supabase.auth.getSession();
104→        await fetch(`${P_AICUJP_ORIGIN}/api/push/subscribe`, {
105→          method: 'POST',
106→          headers: {
107→            'Content-Type': 'application/json',
108→            'Authorization': `Bearer ${session?.access_token}`,
109→          },
110→          body: JSON.stringify({
111→            endpoint: sub.endpoint,
112→            p256dh: btoa(String.fromCharCode(...new Uint8Array(key))),
113→            auth: btoa(String.fromCharCode(...new Uint8Array(auth))),
114→          }),
115→        });
116→        setPushEnabled(true);
117→      }
118→    } catch (err) {
119→      console.error('Push toggle error:', err);
120→    } finally {
121→      setPushLoading(false);
122→    }
123→  }, [pushEnabled, pushLoading]);
124→
125→  const handleSignOut = async () => {
126→    await signOut();
127→    navigate('/');
128→  };
129→
130→  if (!isAuthenticated) {
131→    return (
