137→          <button onClick={() => navigate('/login')} style={styles.primaryBtn}>
138→            ログイン / 新規登録
139→          </button>
140→        </div>
141→      </div>
142→    );
143→  }
144→
145→  return (
146→    <div style={styles.container}>
147→      <div style={styles.card}>
148→        {/* Avatar */}
149→        {user.user_metadata?.avatar_url ? (
150→          <img
151→            src={user.user_metadata.avatar_url}
152→            alt=""
153→            style={styles.avatarImg}
154→          />
155→        ) : (
156→          <div style={styles.avatar}>
157→            {(user.user_metadata?.full_name?.[0] || user.email?.[0] || '?').toUpperCase()}
158→          </div>
159→        )}
160→        <h2 style={styles.heading}>
161→          {user.user_metadata?.full_name || user.email}
162→        </h2>
163→        {user.user_metadata?.full_name && user.email && (
164→          <p style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 4, wordBreak: 'break-all' }}>
165→            {user.email}
166→          </p>
167→        )}
168→        <p style={styles.desc}>
169→          {user.app_metadata?.provider === 'discord' ? 'Discord連携済み'
170→            : user.app_metadata?.provider === 'google' ? 'Google連携済み'
171→            : 'メール認証済み'}
172→          {' · '}登録日: {new Date(user.created_at).toLocaleDateString('ja-JP')}
173→        </p>
174→
175→        {/* Display name editing */}
176→        <div style={{
177→          background: 'var(--bg-primary)',
178→          borderRadius: 12,
179→          padding: '14px 16px',
180→          marginBottom: 16,
181→          textAlign: 'left',
182→        }}>
183→          <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-secondary)', display: 'block', marginBottom: 6 }}>
184→            AICUに読んで欲しい名前
185→          </label>
186→          <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
187→            <input
188→              type="text"
189→              value={displayName}
190→              onChange={e => setDisplayName(e.target.value)}
191→              placeholder={user.user_metadata?.full_name || user.email?.split('@')[0] || '名前'}
192→              maxLength={30}
193→              style={{
194→                flex: 1,
195→                padding: '8px 12px',
196→                fontSize: 14,
197→                border: '1px solid var(--border)',
