import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../hooks/useAuth';
import { useArticleActions } from '../hooks/useArticleActions';
import { useNavigate, Link } from 'react-router-dom';
import { supabase } from '../utils/supabase';

const VAPID_PUBLIC_KEY = import.meta.env.VITE_VAPID_PUBLIC_KEY;
const P_AICUJP_ORIGIN = import.meta.env.DEV ? 'http://localhost:3200' : 'https://p.aicu.jp';

export default function Profile() {
  const { user, signOut, isAuthenticated } = useAuth();
  const { bookmarkCount } = useArticleActions();
  const navigate = useNavigate();

  const [pushEnabled, setPushEnabled] = useState(false);
  const [pushLoading, setPushLoading] = useState(false);
  const [pushSupported] = useState(
    () => 'serviceWorker' in navigator && 'PushManager' in window && !!VAPID_PUBLIC_KEY
  );

  // Display name editing
  const [displayName, setDisplayName] = useState('');
  const [displayNameSaved, setDisplayNameSaved] = useState(false);
  const [displayNameLoading, setDisplayNameLoading] = useState(false);

  useEffect(() => {
    if (!user) return;
    supabase
      .from('profiles')
      .select('display_name')
      .eq('id', user.id)
      .single()
      .then(({ data }) => {
        if (data?.display_name) setDisplayName(data.display_name);
      });
  }, [user]);

  const handleSaveDisplayName = useCallback(async () => {
    if (displayNameLoading || !user) return;
    setDisplayNameLoading(true);
    setDisplayNameSaved(false);
    try {
      await supabase
        .from('profiles')
        .upsert({ id: user.id, display_name: displayName.trim() || null }, { onConflict: 'id' });
      setDisplayNameSaved(true);
      setTimeout(() => setDisplayNameSaved(false), 2000);
    } catch (err) {
      console.error('Failed to save display_name:', err);
    } finally {
      setDisplayNameLoading(false);
    }
  }, [displayName, displayNameLoading, user]);
  // iOS Safari: push only works in standalone (A2HS) mode
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent);
  const isStandalone = window.matchMedia('(display-mode: standalone)').matches || navigator.standalone;
  const isIOSBrowser = isIOS && !isStandalone;

  // Check current push subscription state on mount
  useEffect(() => {
    if (!pushSupported || !isAuthenticated) return;
    navigator.serviceWorker.ready.then((reg) => {
      reg.pushManager.getSubscription().then((sub) => {
        setPushEnabled(!!sub);
      });
    });
  }, [pushSupported, isAuthenticated]);

  const handlePushToggle = useCallback(async () => {
    if (pushLoading) return;
    setPushLoading(true);
    try {
      const reg = await navigator.serviceWorker.ready;
      if (pushEnabled) {
        // Unsubscribe
        const sub = await reg.pushManager.getSubscription();
        if (sub) {
          const { data: { session } } = await supabase.auth.getSession();
          await fetch(`${P_AICUJP_ORIGIN}/api/push/unsubscribe`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${session?.access_token}`,
            },
            body: JSON.stringify({ endpoint: sub.endpoint }),
          });
          await sub.unsubscribe();
        }
        setPushEnabled(false);
      } else {
        // Subscribe
        const permission = await Notification.requestPermission();
        if (permission !== 'granted') {
          setPushLoading(false);
          return;
        }
        const sub = await reg.pushManager.subscribe({
          userVisibleOnly: true,
          applicationServerKey: VAPID_PUBLIC_KEY,
        });
        const key = sub.getKey('p256dh');
        const auth = sub.getKey('auth');
        const { data: { session } } = await supabase.auth.getSession();
        await fetch(`${P_AICUJP_ORIGIN}/api/push/subscribe`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${session?.access_token}`,
          },
          body: JSON.stringify({
            endpoint: sub.endpoint,
            p256dh: btoa(String.fromCharCode(...new Uint8Array(key))),
            auth: btoa(String.fromCharCode(...new Uint8Array(auth))),
          }),
        });
        setPushEnabled(true);
      }
    } catch (err) {
      console.error('Push toggle error:', err);
    } finally {
      setPushLoading(false);
    }
  }, [pushEnabled, pushLoading]);

  const handleSignOut = async () => {
    await signOut();
    navigate('/');
  };

  if (!isAuthenticated) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <p style={{ fontSize: 48, marginBottom: 16 }}>👤</p>
          <h2 style={styles.heading}>アカウント</h2>
          <p style={styles.desc}>ログインして、お気に入り記事の保存やプレミアム機能をご利用ください。</p>
          <button onClick={() => navigate('/login')} style={styles.primaryBtn}>
            ログイン / 新規登録
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        {/* Avatar */}
        {user.user_metadata?.avatar_url ? (
          <img
            src={user.user_metadata.avatar_url}
            alt=""
            style={styles.avatarImg}
          />
        ) : (
          <div style={styles.avatar}>
            {(user.user_metadata?.full_name?.[0] || user.email?.[0] || '?').toUpperCase()}
          </div>
        )}
        <h2 style={styles.heading}>
          {user.user_metadata?.full_name || user.email}
        </h2>
        {user.user_metadata?.full_name && user.email && (
          <p style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 4, wordBreak: 'break-all' }}>
            {user.email}
          </p>
        )}
        <p style={styles.desc}>
          {user.app_metadata?.provider === 'discord' ? 'Discord連携済み'
            : user.app_metadata?.provider === 'google' ? 'Google連携済み'
            : 'メール認証済み'}
          {' · '}登録日: {new Date(user.created_at).toLocaleDateString('ja-JP')}
        </p>

        {/* Display name editing */}
        <div style={{
          background: 'var(--bg-primary)',
          borderRadius: 12,
          padding: '14px 16px',
          marginBottom: 16,
          textAlign: 'left',
        }}>
          <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-secondary)', display: 'block', marginBottom: 6 }}>
            AICUに読んで欲しい名前
          </label>
          <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
            <input
              type="text"
              value={displayName}
              onChange={e => setDisplayName(e.target.value)}
              placeholder={user.user_metadata?.full_name || user.email?.split('@')[0] || '名前'}
              maxLength={30}
              style={{
                flex: 1,
                padding: '8px 12px',
                fontSize: 14,
                border: '1px solid var(--border)',
                borderRadius: 8,
                background: 'var(--bg-card)',
                color: 'var(--text-primary)',
                outline: 'none',
                fontFamily: "'Noto Sans JP', sans-serif",
              }}
              onKeyDown={e => { if (e.key === 'Enter') handleSaveDisplayName(); }}
            />
            <button
              onClick={handleSaveDisplayName}
              disabled={displayNameLoading}
              style={{
                padding: '8px 16px',
                fontSize: 13,
                fontWeight: 600,
                fontFamily: "'Noto Sans JP', sans-serif",
                background: displayNameSaved ? '#22c55e' : 'var(--aicu-rose)',
                color: '#fff',
                border: 'none',
                borderRadius: 8,
                cursor: displayNameLoading ? 'wait' : 'pointer',
                whiteSpace: 'nowrap',
                transition: 'background 0.2s',
              }}
            >
              {displayNameSaved ? '保存済み' : displayNameLoading ? '...' : '保存'}
            </button>
          </div>
          <p style={{ fontSize: 11, color: 'var(--text-tertiary)', marginTop: 6 }}>
            新着通知に「○○さんへの新着」と表示されます
          </p>
        </div>

        {/* AICU Points / Wix Member Status */}
        <a
          href="https://p.aicu.jp/dashboard"
          target="_blank"
          rel="noopener"
          style={styles.pointsCard}
        >
          <div style={styles.pointsInner}>
            <p style={styles.pointsLabel}>AICUポイント / 会員情報</p>
            <p style={styles.pointsValue}>
              確認する <span style={{ fontSize: 16, opacity: 0.8 }}>→</span>
            </p>
            <p style={styles.pointsNote}>
              ポイント残高・購入履歴・会員プランを確認できます
            </p>
          </div>
        </a>

        {/* Plan info */}
        <div style={styles.planBadge}>
          <span style={styles.planLabel}>Free</span>
          <span style={styles.planDesc}>基本機能をご利用中</span>
        </div>

        {/* Menu items */}
        <div style={styles.menuGroup}>
          <Link to="/bookmarks" style={styles.menuItem}>
            <span>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
              </svg>
            </span>
            <span style={{ flex: 1 }}>キニナル記事</span>
            {bookmarkCount > 0 && (
              <span style={{
                fontSize: 11,
                fontWeight: 700,
                color: 'var(--aicu-rose)',
                background: 'rgba(65,201,180,0.12)',
                padding: '2px 8px',
                borderRadius: 8,
                minWidth: 20,
                textAlign: 'center',
              }}>
                {bookmarkCount}
              </span>
            )}
            <span style={{ color: 'var(--text-tertiary)', fontSize: 16 }}>›</span>
          </Link>
          {pushSupported ? (
            <div style={styles.menuItem} onClick={handlePushToggle}>
              <span>🔔</span>
              <span style={{ flex: 1 }}>プッシュ通知</span>
              {pushLoading ? (
                <span style={{ fontSize: 12, color: 'var(--text-tertiary)' }}>...</span>
              ) : (
                <span style={{
                  width: 44,
                  height: 26,
                  borderRadius: 13,
                  background: pushEnabled ? 'var(--aicu-rose)' : 'var(--bg-primary)',
                  display: 'inline-flex',
                  alignItems: 'center',
                  padding: 2,
                  transition: 'background 0.2s',
                  cursor: 'pointer',
                  border: pushEnabled ? 'none' : '1px solid var(--border)',
                }}>
                  <span style={{
                    width: 22,
                    height: 22,
                    borderRadius: '50%',
                    background: '#fff',
                    boxShadow: '0 1px 3px rgba(0,0,0,0.15)',
                    transform: pushEnabled ? 'translateX(18px)' : 'translateX(0)',
                    transition: 'transform 0.2s',
                  }} />
                </span>
              )}
            </div>
          ) : isIOSBrowser ? (
            <div style={{ ...styles.menuItem, flexDirection: 'column', alignItems: 'flex-start', gap: 6 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <span>🔔</span>
                <span>プッシュ通知</span>
              </div>
              <p style={{ fontSize: 11, color: 'var(--text-secondary)', lineHeight: 1.5, margin: 0, paddingLeft: 28 }}>
                共有ボタン
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={{ verticalAlign: 'middle', margin: '0 2px' }}><path d="M4 12v8a2 2 0 002 2h12a2 2 0 002-2v-8"/><polyline points="16 6 12 2 8 6"/><line x1="12" y1="2" x2="12" y2="15"/></svg>
                →「ホーム画面に追加」でアプリ化すると通知を受け取れます
              </p>
            </div>
          ) : (
            <MenuItem icon="🔔" label="プッシュ通知" badge="非対応" />
          )}
        </div>

        {/* Links */}
        <div style={styles.menuGroup}>
          <a href="https://p.aicu.jp/dashboard" target="_blank" rel="noopener" style={styles.menuItem}>
            <span>💎</span>
            <span style={{ flex: 1 }}>ポイント・会員管理</span>
            <span style={{ color: 'var(--text-tertiary)', fontSize: 16 }}>→</span>
          </a>
          <a href="https://j.aicu.ai/JoinDiscord" target="_blank" rel="noopener" style={styles.menuItem}>
            <span>💬</span>
            <span style={{ flex: 1 }}>Discordコミュニティ</span>
            <span style={{ color: 'var(--text-tertiary)', fontSize: 16 }}>→</span>
          </a>
          <a href="https://aicu.blog/category/all-products" target="_blank" rel="noopener" style={styles.menuItem}>
            <span>🛒</span>
            <span style={{ flex: 1 }}>ストア</span>
            <span style={{ color: 'var(--text-tertiary)', fontSize: 16 }}>→</span>
          </a>
        </div>

        <div style={styles.menuGroup}>
          <a href="https://aicu.ai" target="_blank" rel="noopener" style={styles.menuItem}>
            <span>🌐</span>
            <span style={{ flex: 1 }}>AICU Webサイト</span>
            <span style={{ color: 'var(--text-tertiary)', fontSize: 16 }}>→</span>
          </a>
          <a href="https://note.com/aicu" target="_blank" rel="noopener" style={styles.menuItem}>
            <span>📝</span>
            <span style={{ flex: 1 }}>note.com/aicu</span>
            <span style={{ color: 'var(--text-tertiary)', fontSize: 16 }}>→</span>
          </a>
        </div>

        <button onClick={handleSignOut} style={styles.logoutBtn}>
          ログアウト
        </button>

        <p style={styles.version}>AICU App v0.2.0 β</p>
        <p style={styles.legalLinks}>
          <a href="https://www.aicu.blog/terms/plan-free" target="_blank" rel="noopener" style={styles.legalLink}>利用規約</a>
          {' / '}
          <a href="https://corp.aicu.ai/ja/privacy" target="_blank" rel="noopener" style={styles.legalLink}>プライバシー</a>
          {' / '}
          <a href="https://www.aicu.blog/terms/legal" target="_blank" rel="noopener" style={styles.legalLink}>法的免責</a>
        </p>
      </div>
    </div>
  );
}

function MenuItem({ icon, label, badge, onClick }) {
  return (
    <div style={styles.menuItem} onClick={onClick}>
      <span>{icon}</span>
      <span style={{ flex: 1 }}>{label}</span>
      {badge && (
        <span style={{
          fontSize: 10,
          color: 'var(--text-tertiary)',
          background: 'var(--bg-primary)',
          padding: '2px 8px',
          borderRadius: 8,
        }}>
          {badge}
        </span>
      )}
    </div>
  );
}

const styles = {
  container: {
    minHeight: '100vh',
