import { useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useArticleActions } from '../hooks/useArticleActions';
import { ArticleCardCompact } from '../components/ArticleCard';

export default function Bookmarks() {
  const navigate = useNavigate();
  const { bookmarks, bookmarkCount, isRead, markRead, isBookmarked, toggleBookmark } = useArticleActions();

  const handleOpen = useCallback((article) => {
    markRead(article);
    window.open(article.link, '_blank', 'noopener');
  }, [markRead]);

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={{
        position: 'sticky',
        top: 0,
        zIndex: 50,
        background: 'var(--bg-nav)',
        backdropFilter: 'blur(20px) saturate(180%)',
        WebkitBackdropFilter: 'blur(20px) saturate(180%)',
        borderBottom: '0.5px solid var(--border)',
      }}>
        <div style={{
          maxWidth: 640,
          margin: '0 auto',
          padding: '12px 16px',
          display: 'flex',
          alignItems: 'center',
          gap: 12,
        }}>
          <button
            onClick={() => navigate(-1)}
            style={{
              background: 'none',
              border: 'none',
              padding: 4,
              cursor: 'pointer',
              color: 'var(--text-primary)',
            }}
          >
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="15 18 9 12 15 6"/>
            </svg>
          </button>
          <h1 style={{
            fontSize: 17,
            fontWeight: 700,
            color: 'var(--text-primary)',
            flex: 1,
          }}>
            キニナル記事
          </h1>
          {bookmarkCount > 0 && (
            <span style={{
              fontSize: 12,
              fontWeight: 700,
              color: 'var(--aicu-rose)',
              background: 'rgba(65,201,180,0.12)',
              padding: '2px 10px',
              borderRadius: 10,
            }}>
              {bookmarkCount}
            </span>
          )}
        </div>
      </header>

      {/* Content */}
      <main style={{ maxWidth: 640, margin: '0 auto' }}>
        {bookmarkCount === 0 ? (
          <div style={{
            padding: 48,
            textAlign: 'center',
            color: 'var(--text-tertiary)',
          }}>
            <p style={{ fontSize: 36, marginBottom: 12 }}>
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" style={{ color: 'var(--text-tertiary)', opacity: 0.5 }}>
                <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
              </svg>
            </p>
            <p style={{ fontSize: 14, marginBottom: 8 }}>キニナル記事はまだありません</p>
            <p style={{ fontSize: 12, color: 'var(--text-tertiary)' }}>
              記事のブックマークアイコンをタップして保存しましょう
            </p>
          </div>
        ) : (
          <div style={{
            background: 'var(--bg-card)',
            borderRadius: 'var(--radius)',
            overflow: 'hidden',
            margin: '16px 0',
            boxShadow: 'var(--shadow-sm)',
          }}>
            {bookmarks.map((article, i) => (
              <ArticleCardCompact
                key={article.id || article.link}
                article={article}
                index={i}
                onOpen={handleOpen}
                isRead={isRead(article.id || article.link)}
                isBookmarked={isBookmarked(article.id || article.link)}
                onBookmark={toggleBookmark}
              />
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

