  1→import { useState, useEffect, useCallback } from 'react';
  2→import { Link } from 'react-router-dom';
  3→import { useAuth } from '../hooks/useAuth';
  4→import { useFeed } from '../hooks/useFeed';
  5→import { useArticleActions } from '../hooks/useArticleActions';
  6→import { supabase } from '../utils/supabase';
  7→import { formatDate } from '../utils/rss';
  8→
  9→const REACTIONS = [
 10→  { emoji: '👍', label: 'いいね' },
 11→  { emoji: '🔥', label: '熱い' },
 12→  { emoji: '💡', label: '参考になった' },
 13→  { emoji: '🤔', label: 'もっと知りたい' },
 14→];
 15→
 16→function trackEvent(action, params) {
 17→  if (window.gtag) window.gtag('event', action, params);
 18→}
 19→
 20→export default function News() {
 21→  const { user, isAuthenticated } = useAuth();
 22→  const { articles, loading, updatedAt } = useFeed('aicu');
 23→  const { isRead, markRead, isBookmarked, toggleBookmark, bookmarkCount } = useArticleActions();
 24→  const [displayName, setDisplayName] = useState(null);
 25→
 26→  // Fetch display_name from profiles (Supabase)
 27→  useEffect(() => {
 28→    if (!user) return;
 29→    supabase
 30→      .from('profiles')
 31→      .select('display_name')
 32→      .eq('id', user.id)
 33→      .single()
 34→      .then(({ data }) => {
 35→        if (data?.display_name) {
 36→          setDisplayName(data.display_name);
 37→        } else {
 38→          // Fallback: auth metadata name
 39→          setDisplayName(
 40→            user.user_metadata?.full_name
 41→            || user.user_metadata?.name
 42→            || user.email?.split('@')[0]
 43→            || null
 44→          );
 45→        }
 46→      });
 47→  }, [user]);
 48→
 49→  const top2 = articles.slice(0, 2);
 50→
 51→  const handleOpen = useCallback((article) => {
 52→    markRead(article);
 53→    trackEvent('news_article_click', { article_title: article.title });
 54→    window.open(article.link, '_blank', 'noopener');
 55→  }, [markRead]);
 56→
 57→  // Track page view
 58→  useEffect(() => {
 59→    trackEvent('page_view', { page_title: 'AICU News', page_path: '/news' });
 60→  }, []);
 61→
 62→  return (
 63→    <div style={{ minHeight: '100vh' }}>
 64→      {/* Header — 1 line: back + greeting + updated */}
 65→      <header style={{
 66→        position: 'sticky',
 67→        top: 0,
 68→        zIndex: 50,
 69→        background: 'var(--bg-nav)',
 70→        backdropFilter: 'blur(20px) saturate(180%)',
 71→        WebkitBackdropFilter: 'blur(20px) saturate(180%)',
 72→        borderBottom: '0.5px solid var(--border)',
 73→      }}>
 74→        <div style={{
 75→          maxWidth: 640,
 76→          margin: '0 auto',
 77→          padding: '10px 16px',
 78→          display: 'flex',
 79→          alignItems: 'center',
 80→          gap: 8,
 81→        }}>
 82→          <Link to="/" style={{
 83→            padding: 4,
 84→            color: 'var(--text-primary)',
 85→            display: 'flex',
 86→            alignItems: 'center',
 87→            flexShrink: 0,
 88→          }}>
 89→            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
 90→              <polyline points="15 18 9 12 15 6"/>
 91→            </svg>
 92→          </Link>
 93→          <div style={{ flex: 1, minWidth: 0 }}>
 94→            <span style={{
 95→              fontSize: 15,
 96→              fontWeight: 700,
 97→              color: 'var(--text-primary)',
 98→            }}>
 99→              {displayName
100→                ? <>{displayName}さんへの新着</>
101→                : <>今日の新着</>
102→              }
103→            </span>
104→            {!displayName && isAuthenticated && (
105→              <Link to="/profile" style={{
106→                fontSize: 10,
107→                color: 'var(--aicu-rose)',
108→                textDecoration: 'none',
109→                marginLeft: 6,
110→              }}>
111→                名前を設定
112→              </Link>
113→            )}
114→          </div>
115→          {updatedAt && (
116→            <span style={{ fontSize: 10, color: 'var(--text-tertiary)', flexShrink: 0, whiteSpace: 'nowrap' }}>
117→              {formatUpdatedAt(updatedAt)}
118→            </span>
119→          )}
120→        </div>
121→      </header>
122→
123→      <main style={{
124→        maxWidth: 640,
125→        margin: '0 auto',
126→        padding: 16,
127→      }}>
128→        {/* Loading */}
129→        {loading && !top2.length && (
130→          <div style={{ padding: 32, textAlign: 'center', color: 'var(--text-tertiary)' }}>
131→            読み込み中...
132→          </div>
133→        )}
134→
135→        {/* Articles */}
136→        {top2.map((article, i) => (
137→          <NewsCard
138→            key={article.id}
139→            article={article}
140→            index={i}
141→            onOpen={handleOpen}
142→            isRead={isRead(article.id || article.link)}
143→            isBookmarked={isBookmarked(article.id || article.link)}
144→            onBookmark={() => {
145→              toggleBookmark(article);
146→              trackEvent('news_bookmark', { article_title: article.title });
147→            }}
148→          />
149→        ))}
150→
151→        {/* Bookmarks link */}
152→        <Link
153→          to="/bookmarks"
154→          style={{
155→            display: 'flex',
156→            alignItems: 'center',
157→            justifyContent: 'center',
158→            gap: 8,
159→            padding: '14px 20px',
160→            marginTop: 4,
161→            borderRadius: 12,
162→            background: 'var(--bg-card)',
163→            boxShadow: 'var(--shadow-sm)',
164→            textDecoration: 'none',
165→            color: 'var(--text-primary)',
166→            fontSize: 14,
167→            fontWeight: 600,
168→          }}
169→        >
170→          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--aicu-rose)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
171→            <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
172→          </svg>
173→          後で読むリスト
174→          {bookmarkCount > 0 && (
175→            <span style={{
176→              fontSize: 11,
177→              fontWeight: 700,
178→              color: '#fff',
179→              background: 'var(--aicu-rose)',
180→              padding: '2px 8px',
181→              borderRadius: 10,
182→            }}>
183→              {bookmarkCount}
184→            </span>
185→          )}
186→        </Link>
187→
188→        {/* More articles link */}
189→        {articles.length > 2 && (
190→          <Link
191→            to="/media"
192→            style={{
193→              display: 'block',
194→              textAlign: 'center',
195→              padding: '14px',
