255→}
256→
257→function NewsCard({ article, index, onOpen, isRead, isBookmarked, onBookmark }) {
258→  const [reacted, setReacted] = useState(() => {
259→    try {
260→      const saved = JSON.parse(localStorage.getItem('news_reactions') || '{}');
261→      return saved[article.id || article.link] || null;
262→    } catch { return null; }
263→  });
264→
265→  const handleReaction = (emoji) => {
266→    const key = article.id || article.link;
267→    const next = reacted === emoji ? null : emoji;
268→    setReacted(next);
269→    trackEvent('news_reaction', { article_title: article.title, reaction: emoji });
270→    try {
271→      const saved = JSON.parse(localStorage.getItem('news_reactions') || '{}');
272→      if (next) saved[key] = next;
273→      else delete saved[key];
274→      localStorage.setItem('news_reactions', JSON.stringify(saved));
275→    } catch {}
276→  };
277→
278→  return (
279→    <div style={{
280→      background: 'var(--bg-card)',
281→      borderRadius: 16,
282→      overflow: 'hidden',
283→      boxShadow: 'var(--shadow-sm)',
284→      marginBottom: 16,
285→    }}>
286→      {/* Thumbnail */}
287→      {article.thumbnail && (
288→        <div
289→          style={{ cursor: 'pointer', overflow: 'hidden' }}
290→          onClick={() => onOpen(article)}
291→        >
292→          <img
293→            src={article.thumbnail}
294→            alt=""
295→            loading={index === 0 ? 'eager' : 'lazy'}
296→            style={{
297→              width: '100%',
298→              aspectRatio: '16/9',
299→              objectFit: 'cover',
300→              display: 'block',
301→              opacity: isRead ? 0.6 : 1,
302→              transition: 'opacity 0.2s',
303→            }}
304→            onError={e => { e.target.style.display = 'none'; }}
305→          />
306→        </div>
307→      )}
308→
309→      {/* Content */}
310→      <div style={{ padding: '14px 16px' }}>
311→        {/* Top row: badge + bookmark */}
312→        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
313→          <div style={{
314→            display: 'inline-block',
315→            padding: '2px 8px',
316→            borderRadius: 6,
317→            background: index === 0 ? 'var(--aicu-rose)' : 'var(--bg-primary)',
318→            color: index === 0 ? '#fff' : 'var(--text-secondary)',
319→            fontSize: 10,
320→            fontWeight: 700,
321→          }}>
322→            {index === 0 ? 'NEW' : `#${index + 1}`}
323→          </div>
324→          <button
