import { BrowserRouter, Routes, Route, useLocation } from 'react-router-dom';
import { useEffect } from 'react';
import { AuthProvider } from './hooks/useAuth';
import Layout from './components/Layout';
import Service from './pages/Service';
import Home from './pages/Home';
import Login from './pages/Login';
import Profile from './pages/Profile';
import ArticleView from './pages/ArticleView';
import About from './pages/About';
import Bookmarks from './pages/Bookmarks';
import News from './pages/News';
import CreateVoice from './pages/CreateVoice';
import AiCuty from './pages/AiCuty';
import Events from './pages/Events';
import EventArchive from './pages/EventArchive';
import Corp from './pages/Corp';
import CorpMedia from './pages/CorpMedia';
import './index.css';

function GtagRouteTracker() {
  const location = useLocation();
  useEffect(() => {
    if (window.gtag) {
      window.gtag('config', 'G-9Z2S3ZBGEV', { page_path: location.pathname });
    }
  }, [location]);
  return null;
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <GtagRouteTracker />
        <Routes>
          <Route element={<Layout />}>
            <Route path="/" element={<Service />} />
            <Route path="/media" element={<Home />} />
            <Route path="/search" element={<ArticleView />} />
            <Route path="/profile" element={<Profile />} />
            <Route path="/login" element={<Login />} />
            <Route path="/bookmarks" element={<Bookmarks />} />
            <Route path="/news" element={<News />} />
            <Route path="/about" element={<About />} />
            <Route path="/aicuty" element={<AiCuty />} />
            <Route path="/e" element={<Events />} />
            <Route path="/e/:slug" element={<EventArchive />} />
            <Route path="/corp" element={<Corp />} />
            <Route path="/corp/media" element={<CorpMedia />} />
            <Route path="/create/voice" element={<CreateVoice />} />
          </Route>
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}

