import { useEffect } from 'react';
import { useParams, Navigate, Link } from 'react-router-dom';
import { getEventByShortcode } from '../data/events';
import CreateVoice from './CreateVoice';
import Footer from '../components/Footer';
import usePageMeta from '../hooks/usePageMeta';

export default function EventArchive() {
  const { slug } = useParams();
  const event = getEventByShortcode(slug);
  const isLive = event?.status === 'live' && event?.staticPath;

  // Live event → full-page navigation to static HTML
  useEffect(() => {
    if (isLive) {
      window.location.href = event.staticPath;
    }
  }, [isLive, event]);

  // GA4 page_view for archived events
  useEffect(() => {
    if (event && !isLive && window.gtag) {
      window.gtag('event', 'page_view', {
        page_title: event.title,
        page_location: window.location.href,
        event_shortcode: event.shortcode,
        event_status: event.status,
      });
    }
  }, [event, isLive]);

  if (!event) {
    return <Navigate to="/e" replace />;
  }

  if (isLive) {
    return null;
  }

  if (event.shortcode === 'VoiceAudition') {
    return <CreateVoice archived />;
  }

  return <GenericArchive event={event} />;
}

