            margin: '16px 0 0',
            padding: '10px 14px',
            borderRadius: 'var(--radius-sm)',
            background: 'var(--bg-card)',
            border: '1px solid var(--border)',
            textAlign: 'center',
            fontSize: 13,
            fontWeight: 600,
            color: 'var(--text-tertiary)',
          }}>
            このイベントは終了しました — <Link to="/e" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>イベント一覧</Link>
          </div>
        )}

        {/* Hero */}
        <section style={{ textAlign: 'center', padding: '20px 0 16px' }}>
          <div style={{
            display: 'inline-block',
            padding: '5px 14px',
            borderRadius: 20,
            background: 'linear-gradient(135deg, #FFB7C5, #9370DB)',
            color: '#fff',
            fontSize: 11,
            fontWeight: 700,
            letterSpacing: '0.04em',
            marginBottom: 10,
          }}>
            AiCuty Voice Audition
          </div>
          <h1 style={{ fontSize: 20, fontWeight: 700, color: 'var(--text-primary)', lineHeight: 1.4 }}>
            推しの声を、あなたが決める。
          </h1>
          <p style={{ fontSize: 13, color: 'var(--text-secondary)', marginTop: 6, lineHeight: 1.5 }}>
            AI音声モデル「Qwen3-TTS」で AiCuty のボイスを生成
          </p>
          <div style={{
            display: 'inline-flex',
            gap: 6,
            marginTop: 10,
            fontSize: 11,
          }}>
            <span style={{
              padding: '3px 10px',
              borderRadius: 8,
              background: 'var(--aicu-rose-light)',
              color: 'var(--aicu-rose-dark)',
              fontWeight: 600,
            }}>
              Basic会員以上は無料
            </span>
            <span style={{
              padding: '3px 10px',
              borderRadius: 8,
              background: 'var(--bg-card)',
              border: '1px solid var(--border)',
              color: 'var(--text-tertiary)',
            }}>
              #AiCuty でXに投稿
            </span>
          </div>
        </section>

        {/* Cover image */}
        <img
          src="/CoverArtWithText.webp"
          alt="AiCuty キャラクターボイスオーディション"
          width={640}
          height={357}
          style={{
            width: '100%',
            height: 'auto',
            borderRadius: 'var(--radius)',
            boxShadow: 'var(--shadow-sm)',
            marginBottom: 20,
          }}
        />

        {/* CTA: Tool link or 準備中 */}
        <section style={{
          marginBottom: 24,
          padding: '20px 16px',
          borderRadius: 'var(--radius)',
          background: 'linear-gradient(135deg, var(--aicu-rose-light), var(--bg-card))',
          border: '1px solid var(--aicu-rose)',
          textAlign: 'center',
        }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)', marginBottom: 8 }}>
            ボイス生成ツール
          </div>
          <div style={{
            display: 'inline-block',
            padding: '4px 12px',
            borderRadius: 8,
            background: '#FFF3CD',
            color: '#856404',
            fontSize: 11,
            fontWeight: 600,
            marginBottom: 12,
          }}>
            準備中
          </div>
          <p style={{ fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.6 }}>
            ボイス生成ツールは現在準備中です。公開まで今しばらくお待ちください。
          </p>
          <a
