                    {selected.nameJp} / {selected.birthday} / {selected.personality}
                  </div>
                </div>
              </div>
              <div style={{ padding: '12px 16px' }}>
                <p style={{ fontSize: 12, color: 'var(--text-primary)', lineHeight: 1.6, marginBottom: 10 }}>
                  {selected.sampleText}
