                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                  {[
                    `speaker=${selected.speaker}`,
                    `seed=${selected.seed}`,
                  ].map((tag) => (
                    <span key={tag} style={{
                      padding: '2px 6px',
                      borderRadius: 4,
                      background: `${selected.color}12`,
                      fontSize: 9,
                      fontFamily: 'monospace',
                      color: 'var(--text-tertiary)',
                    }}>
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          </section>
        )}

        {/* Pricing */}
        <section style={{ marginBottom: 32 }}>
