            overflow: 'hidden',
          }}>
            {eventInfo.map((row, i) => (
              <div key={row.label} style={{
                display: 'flex',
                padding: '12px 16px',
                borderBottom: i < eventInfo.length - 1 ? '0.5px solid var(--border)' : 'none',
                gap: 12,
              }}>
                <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-tertiary)', minWidth: 72, flexShrink: 0 }}>
                  {row.label}
                </div>
                <div style={{ fontSize: 13, color: 'var(--text-primary)', lineHeight: 1.5 }}>
                  {row.value}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* How to participate */}
        <section style={{ marginBottom: 32 }}>
          <SectionTitle>参加方法</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {steps.map((step, i) => (
              <div key={i} style={{
                display: 'flex',
                gap: 14,
                padding: '14px 16px',
                borderRadius: 'var(--radius)',
                background: 'var(--bg-card)',
                boxShadow: 'var(--shadow-sm)',
                alignItems: 'flex-start',
              }}>
                <span style={{
                  width: 28,
                  height: 28,
                  borderRadius: '50%',
                  background: 'var(--aicu-rose)',
                  color: '#fff',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: 13,
                  fontWeight: 700,
                  flexShrink: 0,
                }}>
                  {i + 1}
                </span>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)' }}>{step.title}</div>
                  <div style={{ fontSize: 12, color: 'var(--text-secondary)', marginTop: 2, lineHeight: 1.5 }}>{step.desc}</div>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Links */}
        <section style={{ marginBottom: 32 }}>
          <SectionTitle>関連リンク</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {relatedLinks.map((link) => (
              <a
                key={link.url}
                href={link.url}
                target="_blank"
                rel="noopener"
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 10,
                  padding: '12px 16px',
                  borderRadius: 'var(--radius-sm)',
                  background: 'var(--bg-card)',
                  boxShadow: 'var(--shadow-sm)',
                  textDecoration: 'none',
                  fontSize: 13,
                  color: 'var(--aicu-rose-dark)',
                  fontWeight: 600,
                }}
              >
                <span>{link.icon}</span>
                <span>{link.label}</span>
              </a>
            ))}
          </div>
        </section>

        {/* Terms note */}
        <div style={{
          padding: '14px 16px',
          borderRadius: 'var(--radius)',
          background: 'var(--bg-card)',
          fontSize: 11,
          color: 'var(--text-tertiary)',
          lineHeight: 1.6,
          marginBottom: 32,
        }}>
          個人での学習・実験・楽しむ目的、自分のコンテンツ読み上げ、AIボイス技術の体験はOKです。
          成人向け・なりすまし・ディープフェイク・他者を傷つける使い方はNGです。
          音声生成は<a href="https://www.aicu.jp/terms/aicuty-guideline" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)' }}>AiCuty著作物利用ガイドライン</a>に基づき許諾されます。
        </div>

        <Footer />
      </main>
    </div>
  );
}

