import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { characters } from '../data/characters';
import Footer from '../components/Footer';
import usePageMeta from '../hooks/usePageMeta';

const TOOL_URL = 'https://qwen3tts.aicu.jp';

const jsonLd = {
  '@context': 'https://schema.org',
  '@type': 'SoftwareApplication',
  name: 'AICU AI Voice — AiCuty キャラクターボイス',
  description: 'Qwen3-TTSで推しの声を作ろう！AiCuty 5人に、あなたの解釈で声を与えてください。',
  url: 'https://aicu.jp/create/voice',
  applicationCategory: 'MultimediaApplication',
  operatingSystem: 'Web',
  image: 'https://aicu.jp/CoverArtWithText.webp',
  offers: { '@type': 'Offer', price: '0', priceCurrency: 'JPY', availability: 'https://schema.org/InStock' },
  provider: { '@type': 'Organization', name: 'AICU Japan株式会社', url: 'https://aicu.jp' },
};

export default function CreateVoice({ archived = false }) {
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    const script = document.createElement('script');
    script.type = 'application/ld+json';
    script.textContent = JSON.stringify(jsonLd);
    document.head.appendChild(script);
    return () => script.remove();
  }, []);

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={styles.logo}>AICU</span>
          </Link>
          <span style={styles.headerTitle}>Create / Voice</span>
        </div>
      </header>

      <main style={{ maxWidth: 640, margin: '0 auto', padding: '0 16px 40px' }}>
        {/* Archived banner */}
        {archived && (
          <div style={{
            margin: '16px 0 0',
            padding: '10px 14px',
            borderRadius: 'var(--radius-sm)',
            background: 'var(--bg-card)',
            border: '1px solid var(--border)',
            textAlign: 'center',
            fontSize: 13,
            fontWeight: 600,
            color: 'var(--text-tertiary)',
          }}>
            このイベントは終了しました — <Link to="/e" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>イベント一覧</Link>
          </div>
        )}

        {/* Hero */}
        <section style={{ textAlign: 'center', padding: '20px 0 16px' }}>
          <div style={{
            display: 'inline-block',
            padding: '5px 14px',
            borderRadius: 20,
            background: 'linear-gradient(135deg, #FFB7C5, #9370DB)',
            color: '#fff',
            fontSize: 11,
            fontWeight: 700,
            letterSpacing: '0.04em',
            marginBottom: 10,
          }}>
            AiCuty Voice Audition
          </div>
          <h1 style={{ fontSize: 20, fontWeight: 700, color: 'var(--text-primary)', lineHeight: 1.4 }}>
            推しの声を、あなたが決める。
          </h1>
          <p style={{ fontSize: 13, color: 'var(--text-secondary)', marginTop: 6, lineHeight: 1.5 }}>
            AI音声モデル「Qwen3-TTS」で AiCuty のボイスを生成
          </p>
          <div style={{
            display: 'inline-flex',
            gap: 6,
            marginTop: 10,
            fontSize: 11,
          }}>
            <span style={{
              padding: '3px 10px',
              borderRadius: 8,
              background: 'var(--aicu-rose-light)',
              color: 'var(--aicu-rose-dark)',
              fontWeight: 600,
            }}>
              Basic会員以上は無料
            </span>
            <span style={{
              padding: '3px 10px',
              borderRadius: 8,
              background: 'var(--bg-card)',
              border: '1px solid var(--border)',
              color: 'var(--text-tertiary)',
            }}>
              #AiCuty でXに投稿
            </span>
          </div>
        </section>

        {/* Cover image */}
        <img
          src="/CoverArtWithText.webp"
          alt="AiCuty キャラクターボイスオーディション"
          width={640}
          height={357}
          style={{
            width: '100%',
            height: 'auto',
            borderRadius: 'var(--radius)',
            boxShadow: 'var(--shadow-sm)',
            marginBottom: 20,
          }}
        />

        {/* CTA: Tool link or 準備中 */}
        <section style={{
          marginBottom: 24,
          padding: '20px 16px',
          borderRadius: 'var(--radius)',
          background: 'linear-gradient(135deg, var(--aicu-rose-light), var(--bg-card))',
          border: '1px solid var(--aicu-rose)',
          textAlign: 'center',
        }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)', marginBottom: 8 }}>
            ボイス生成ツール
          </div>
          <div style={{
            display: 'inline-block',
            padding: '4px 12px',
            borderRadius: 8,
            background: '#FFF3CD',
            color: '#856404',
            fontSize: 11,
            fontWeight: 600,
            marginBottom: 12,
          }}>
            準備中
          </div>
          <p style={{ fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.6 }}>
            ボイス生成ツールは現在準備中です。公開まで今しばらくお待ちください。
          </p>
          <a
            href={TOOL_URL}
            target="_blank"
            rel="noopener"
            style={{
              display: 'inline-block',
              marginTop: 12,
              padding: '10px 24px',
              borderRadius: 'var(--radius-sm)',
              background: 'var(--text-tertiary)',
              color: '#fff',
              fontSize: 13,
              fontWeight: 600,
              textDecoration: 'none',
              pointerEvents: 'none',
              opacity: 0.5,
            }}
          >
            ツールを開く（準備中）
          </a>
        </section>

        {/* Characters */}
        <section style={{ marginBottom: 24 }}>
          <SectionTitle>キャラクター</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {characters.map((char) => (
              <button
                key={char.id}
                onClick={() => setSelected(selected?.id === char.id ? null : char)}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 10,
                  padding: '10px 12px',
                  borderRadius: 'var(--radius-sm)',
                  background: selected?.id === char.id
                    ? `linear-gradient(135deg, ${char.color}18, ${char.color}08)`
                    : 'var(--bg-card)',
                  border: selected?.id === char.id
                    ? `2px solid ${char.color}`
                    : '1px solid var(--border)',
                  boxShadow: selected?.id === char.id ? `0 2px 12px ${char.color}20` : 'var(--shadow-sm)',
                  cursor: 'pointer',
                  textAlign: 'left',
                  transition: 'all 0.2s',
                  width: '100%',
                }}
              >
                <img
                  src={`/characters/${char.id}.webp`}
                  alt={char.name}
                  style={{
                    width: 40,
                    height: 40,
                    borderRadius: '50%',
                    objectFit: 'cover',
                    border: `2px solid ${char.color}`,
                    flexShrink: 0,
                  }}
                />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                    <span style={{ fontSize: 14, fontWeight: 700, color: char.color }}>
                      {char.emoji} {char.name}
                    </span>
                    <span style={{ fontSize: 11, color: 'var(--text-tertiary)' }}>
                      {char.nameJp}
                    </span>
                  </div>
                  <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginTop: 2 }}>
                    {char.personality}
                  </div>
                </div>
              </button>
            ))}
          </div>
        </section>

        {/* Selected character detail */}
        {selected && (
          <section style={{ marginBottom: 24 }}>
            <div style={{
              borderRadius: 'var(--radius)',
              background: 'var(--bg-card)',
              boxShadow: 'var(--shadow-sm)',
              overflow: 'hidden',
            }}>
              <div style={{
                padding: '14px 16px',
                background: `linear-gradient(135deg, ${selected.color}15, transparent)`,
                borderBottom: '0.5px solid var(--border)',
                display: 'flex',
                alignItems: 'center',
                gap: 12,
              }}>
                <img
                  src={`/characters/${selected.id}.webp`}
                  alt={selected.name}
                  style={{ width: 48, height: 48, borderRadius: '50%', objectFit: 'cover', border: `2px solid ${selected.color}` }}
                />
                <div>
                  <div style={{ fontSize: 15, fontWeight: 700, color: selected.color }}>
                    {selected.emoji} {selected.name}
                  </div>
                  <div style={{ fontSize: 11, color: 'var(--text-secondary)' }}>
                    {selected.nameJp} / {selected.birthday} / {selected.personality}
                  </div>
                </div>
              </div>
              <div style={{ padding: '12px 16px' }}>
                <p style={{ fontSize: 12, color: 'var(--text-primary)', lineHeight: 1.6, marginBottom: 10 }}>
                  {selected.sampleText}
                </p>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                  {[
                    `speaker=${selected.speaker}`,
                    `seed=${selected.seed}`,
                  ].map((tag) => (
                    <span key={tag} style={{
                      padding: '2px 6px',
                      borderRadius: 4,
                      background: `${selected.color}12`,
                      fontSize: 9,
                      fontFamily: 'monospace',
                      color: 'var(--text-tertiary)',
                    }}>
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          </section>
        )}

        {/* Pricing */}
        <section style={{ marginBottom: 32 }}>
          <SectionTitle>料金</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {pricingTiers.map((tier) => (
              <div key={tier.name} style={{
                padding: '14px 16px',
                borderRadius: 'var(--radius)',
                background: tier.highlight ? 'linear-gradient(135deg, var(--aicu-rose-light), var(--bg-card))' : 'var(--bg-card)',
                border: tier.highlight ? '1px solid var(--aicu-rose)' : '1px solid var(--border)',
                boxShadow: 'var(--shadow-sm)',
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <span style={{ fontSize: 14, fontWeight: 700, color: 'var(--text-primary)' }}>
                    {tier.name}
                  </span>
                  <span style={{ fontSize: 13, fontWeight: 600, color: 'var(--aicu-rose-dark)' }}>
                    {tier.price}
                  </span>
                </div>
                <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginTop: 4, lineHeight: 1.5 }}>
                  {tier.desc}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Tech info */}
        <section style={{ marginBottom: 32 }}>
          <SectionTitle>技術情報</SectionTitle>
          <div style={{
            padding: '14px 16px',
            borderRadius: 'var(--radius)',
            background: 'var(--bg-card)',
            boxShadow: 'var(--shadow-sm)',
          }}>
            <div style={{ fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.8 }}>
              <strong>モデル:</strong> Qwen3-TTS-12Hz-1.7B-CustomVoice (Alibaba Qwen)<br />
              <strong>話者:</strong> 10+ (ono_anna, aiden, dylan, eric, vivian 等)<br />
              <strong>言語:</strong> 日本語, English, 中文, 한국어 等 10言語<br />
              <strong>制御:</strong> Instruction テキストで感情・話速を調整<br />
              <strong>再現性:</strong> Seed 値で同一音声を再現可能
            </div>
          </div>
        </section>

        {/* Event Details */}
        <section style={{ marginBottom: 32 }}>
          <SectionTitle>サービス概要</SectionTitle>
          <div style={{
            borderRadius: 'var(--radius)',
            background: 'var(--bg-card)',
            boxShadow: 'var(--shadow-sm)',
            overflow: 'hidden',
          }}>
            {eventInfo.map((row, i) => (
              <div key={row.label} style={{
                display: 'flex',
                padding: '12px 16px',
                borderBottom: i < eventInfo.length - 1 ? '0.5px solid var(--border)' : 'none',
                gap: 12,
              }}>
                <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-tertiary)', minWidth: 72, flexShrink: 0 }}>
                  {row.label}
                </div>
                <div style={{ fontSize: 13, color: 'var(--text-primary)', lineHeight: 1.5 }}>
                  {row.value}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* How to participate */}
        <section style={{ marginBottom: 32 }}>
          <SectionTitle>参加方法</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {steps.map((step, i) => (
              <div key={i} style={{
                display: 'flex',
                gap: 14,
                padding: '14px 16px',
                borderRadius: 'var(--radius)',
                background: 'var(--bg-card)',
                boxShadow: 'var(--shadow-sm)',
                alignItems: 'flex-start',
              }}>
                <span style={{
                  width: 28,
                  height: 28,
                  borderRadius: '50%',
                  background: 'var(--aicu-rose)',
                  color: '#fff',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: 13,
                  fontWeight: 700,
                  flexShrink: 0,
                }}>
                  {i + 1}
                </span>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-primary)' }}>{step.title}</div>
                  <div style={{ fontSize: 12, color: 'var(--text-secondary)', marginTop: 2, lineHeight: 1.5 }}>{step.desc}</div>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Links */}
        <section style={{ marginBottom: 32 }}>
          <SectionTitle>関連リンク</SectionTitle>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
