import { useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { useFeed } from '../hooks/useFeed';
import { useArticleActions } from '../hooks/useArticleActions';
import ArticleCard, { ArticleCardCompact, SkeletonCard } from '../components/ArticleCard';
import Footer from '../components/Footer';

export default function Home() {
  const { articles, loading, error, refreshing, updatedAt, refresh } = useFeed('aicu');
  const { isRead, markRead, isBookmarked, toggleBookmark } = useArticleActions();
  const [viewMode, setViewMode] = useState('card'); // card | compact

  const handleOpen = useCallback((article) => {
    markRead(article);
    window.open(article.link, '_blank', 'noopener');
  }, [markRead]);

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header */}
      <header style={{
        position: 'sticky',
        top: 0,
        zIndex: 50,
        background: 'var(--bg-nav)',
        backdropFilter: 'blur(20px) saturate(180%)',
        WebkitBackdropFilter: 'blur(20px) saturate(180%)',
        borderBottom: '0.5px solid var(--border)',
      }}>
        <div style={{
          maxWidth: 640,
          margin: '0 auto',
          padding: '12px 16px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}>
          <a href="https://aicu.jp" style={{
            display: 'flex', alignItems: 'center', gap: 10,
            textDecoration: 'none',
          }}>
            <span style={{
              fontFamily: "'Outfit', sans-serif",
              fontSize: 22,
              fontWeight: 800,
              color: 'var(--aicu-rose)',
              letterSpacing: '-0.02em',
            }}>
              AICU
            </span>
            <span style={{
              fontSize: 15,
              fontWeight: 600,
              color: 'var(--text-primary)',
            }}>
              media
            </span>
          </a>

          <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <Link to="/bookmarks" style={{
              background: 'none',
              border: 'none',
              padding: 8,
              cursor: 'pointer',
              color: 'var(--text-secondary)',
              display: 'flex',
              alignItems: 'center',
            }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
              </svg>
            </Link>
            <ViewToggle mode={viewMode} onChange={setViewMode} />
            <button
              onClick={refresh}
              disabled={refreshing}
              style={{
                background: 'none',
                border: 'none',
                padding: 8,
                cursor: 'pointer',
                color: refreshing ? 'var(--text-tertiary)' : 'var(--text-secondary)',
                transition: 'transform 0.3s',
                transform: refreshing ? 'rotate(360deg)' : 'none',
              }}
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="23 4 23 10 17 10"/>
                <path d="M20.49 15a9 9 0 11-2.12-9.36L23 10"/>
              </svg>
            </button>
            <Link to="/profile" style={{
              background: 'none',
              border: 'none',
              padding: 8,
              cursor: 'pointer',
              color: 'var(--text-secondary)',
              display: 'flex',
              alignItems: 'center',
            }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/>
                <circle cx="12" cy="7" r="4"/>
              </svg>
            </Link>
          </div>
        </div>

        {/* Tagline */}
        <div style={{
          maxWidth: 640,
          margin: '0 auto',
          padding: '0 16px 10px',
        }}>
          <p style={{
            fontSize: 13,
            color: 'var(--text-secondary)',
            fontWeight: 400,
          }}>
            生成AI時代に「つくる人をつくる」🎨
          </p>
        </div>
      </header>

      {/* Content */}
      <main style={{
        maxWidth: 640,
        margin: '0 auto',
        padding: viewMode === 'card' ? '16px' : '0',
      }}>
        {/* Error */}
        {error && (
          <div style={{
            padding: 20,
            textAlign: 'center',
            color: 'var(--text-secondary)',
          }}>
            <p style={{ marginBottom: 12 }}>読み込みに失敗しました</p>
            <button
              onClick={refresh}
              style={{
                background: 'var(--aicu-rose)',
                color: '#fff',
                border: 'none',
                padding: '8px 20px',
                borderRadius: 20,
                fontSize: 14,
                fontWeight: 600,
                cursor: 'pointer',
              }}
            >
              再試行
            </button>
          </div>
        )}

        {/* Loading skeletons */}
        {loading && (
          <div style={{
            display: 'grid',
            gap: 16,
            padding: viewMode === 'compact' ? 16 : 0,
          }}>
            {[...Array(4)].map((_, i) => <SkeletonCard key={i} />)}
          </div>
        )}

        {/* Articles - Card mode */}
        {!loading && !error && viewMode === 'card' && (
          <div style={{ display: 'grid', gap: 16 }}>
            {/* Section heading */}
            <h2 style={{
              fontSize: 16,
              fontWeight: 700,
              color: 'var(--text-primary)',
            }}>
              今週の <a href="https://note.com/aicu" target="_blank" rel="noopener" style={{
                color: 'var(--aicu-rose)',
                textDecoration: 'none',
              }}>AICU media</a>
              {updatedAt && (
                <span style={{ fontSize: 10, fontWeight: 400, color: 'var(--text-tertiary)', marginLeft: 8 }}>
                  {(() => { const d = new Date(updatedAt); return isNaN(d) ? '' : `${d.getMonth()+1}/${d.getDate()} ${d.getHours()}:${String(d.getMinutes()).padStart(2,'0')} 更新`; })()}
                </span>
              )}
            </h2>
            {/* Hero – latest article full width */}
            {articles.length > 0 && (
              <ArticleCard
                key={articles[0].id}
                article={articles[0]}
                index={0}
                onOpen={handleOpen}
                isRead={isRead(articles[0].id || articles[0].link)}
                isBookmarked={isBookmarked(articles[0].id || articles[0].link)}
                onBookmark={toggleBookmark}
              />
            )}
            {/* "More" section heading */}
            {articles.length > 1 && (
              <p style={{
                fontSize: 13,
                color: 'var(--text-secondary)',
                lineHeight: 1.6,
              }}>
                クリエイティブAIをエンタメにする! AICU media
              </p>
            )}
            {/* Remaining articles in 2-column grid */}
            {articles.length > 1 && (
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(2, 1fr)',
                gap: 12,
              }}>
                {articles.slice(1).map((article, i) => (
                  <ArticleCard
                    key={article.id}
                    article={article}
                    index={i + 1}
                    onOpen={handleOpen}
                    isRead={isRead(article.id || article.link)}
                    isBookmarked={isBookmarked(article.id || article.link)}
                    onBookmark={toggleBookmark}
                    small
                  />
                ))}
              </div>
            )}
          </div>
        )}

        {/* Articles - Compact mode */}
        {!loading && !error && viewMode === 'compact' && (
          <div style={{
            background: 'var(--bg-card)',
            borderRadius: 'var(--radius)',
            overflow: 'hidden',
            margin: '16px 0',
            boxShadow: 'var(--shadow-sm)',
          }}>
            {articles.map((article, i) => (
              <ArticleCardCompact
                key={article.id}
                article={article}
                index={i}
                onOpen={handleOpen}
                isRead={isRead(article.id || article.link)}
                isBookmarked={isBookmarked(article.id || article.link)}
                onBookmark={toggleBookmark}
              />
            ))}
          </div>
        )}

        {/* Empty state */}
        {!loading && !error && articles.length === 0 && (
          <div style={{
            padding: 48,
            textAlign: 'center',
            color: 'var(--text-tertiary)',
          }}>
            <p style={{ fontSize: 36, marginBottom: 12 }}>📡</p>
            <p>記事が見つかりませんでした</p>
          </div>
        )}

        <Footer />
      </main>
    </div>
  );
}

function ViewToggle({ mode, onChange }) {
  return (
    <div style={{
      display: 'flex',
      background: 'var(--bg-primary)',
      borderRadius: 8,
      padding: 2,
    }}>
      <button
        onClick={() => onChange('card')}
        style={{
          background: mode === 'card' ? 'var(--bg-card)' : 'transparent',
          border: 'none',
          padding: '4px 8px',
          borderRadius: 6,
          cursor: 'pointer',
          color: mode === 'card' ? 'var(--text-primary)' : 'var(--text-tertiary)',
          boxShadow: mode === 'card' ? 'var(--shadow-sm)' : 'none',
          transition: 'all 0.2s',
        }}
        title="カード表示"
      >
        <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2">
          <rect x="3" y="3" width="7" height="7" rx="1"/>
          <rect x="14" y="3" width="7" height="7" rx="1"/>
          <rect x="3" y="14" width="7" height="7" rx="1"/>
          <rect x="14" y="14" width="7" height="7" rx="1"/>
        </svg>
      </button>
      <button
        onClick={() => onChange('compact')}
        style={{
          background: mode === 'compact' ? 'var(--bg-card)' : 'transparent',
          border: 'none',
          padding: '4px 8px',
          borderRadius: 6,
          cursor: 'pointer',
          color: mode === 'compact' ? 'var(--text-primary)' : 'var(--text-tertiary)',
          boxShadow: mode === 'compact' ? 'var(--shadow-sm)' : 'none',
          transition: 'all 0.2s',
        }}
        title="コンパクト表示"
      >
        <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2">
          <line x1="3" y1="6" x2="21" y2="6"/>
          <line x1="3" y1="12" x2="21" y2="12"/>
          <line x1="3" y1="18" x2="21" y2="18"/>
        </svg>
      </button>
    </div>
  );
}

