                isBookmarked={isBookmarked(articles[0].id || articles[0].link)}
                onBookmark={toggleBookmark}
              />
            )}
            {/* "More" section heading */}
            {articles.length > 1 && (
              <p style={{
                fontSize: 13,
                color: 'var(--text-secondary)',
                lineHeight: 1.6,
              }}>
                クリエイティブAIをエンタメにする! AICU media
              </p>
            )}
            {/* Remaining articles in 2-column grid */}
            {articles.length > 1 && (
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(2, 1fr)',
                gap: 12,
              }}>
                {articles.slice(1).map((article, i) => (
                  <ArticleCard
                    key={article.id}
                    article={article}
                    index={i + 1}
                    onOpen={handleOpen}
                    isRead={isRead(article.id || article.link)}
                    isBookmarked={isBookmarked(article.id || article.link)}
                    onBookmark={toggleBookmark}
                    small
                  />
                ))}
              </div>
            )}
          </div>
        )}

        {/* Articles - Compact mode */}
        {!loading && !error && viewMode === 'compact' && (
          <div style={{
            background: 'var(--bg-card)',
            borderRadius: 'var(--radius)',
            overflow: 'hidden',
            margin: '16px 0',
            boxShadow: 'var(--shadow-sm)',
          }}>
            {articles.map((article, i) => (
              <ArticleCardCompact
                key={article.id}
                article={article}
                index={i}
                onOpen={handleOpen}
                isRead={isRead(article.id || article.link)}
                isBookmarked={isBookmarked(article.id || article.link)}
                onBookmark={toggleBookmark}
              />
            ))}
          </div>
        )}

        {/* Empty state */}
        {!loading && !error && articles.length === 0 && (
          <div style={{
            padding: 48,
            textAlign: 'center',
            color: 'var(--text-tertiary)',
          }}>
            <p style={{ fontSize: 36, marginBottom: 12 }}>📡</p>
            <p>記事が見つかりませんでした</p>
          </div>
        )}

        <Footer />
      </main>
    </div>
  );
}

function ViewToggle({ mode, onChange }) {
