                <div style={{ fontSize: 11, color: 'var(--text-tertiary)', marginTop: 4 }}>
                  {p.role}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Footer */}
        <footer style={{
          padding: '28px 0 16px',
          textAlign: 'center',
          fontSize: 11,
          color: 'var(--text-tertiary)',
        }}>
          <div style={{
            display: 'flex',
            flexWrap: 'wrap',
            justifyContent: 'center',
            gap: '4px 14px',
            marginBottom: 14,
          }}>
            {footerLinks.map((f) => (
              <a
                key={f.label}
                href={f.url}
                target="_blank"
                rel="noopener"
                style={{ color: 'var(--text-tertiary)', textDecoration: 'none' }}
              >
                {f.label}
              </a>
            ))}
          </div>
          <p>
            Powered by{' '}
            <a href="https://aicu.jp" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>AICU Japan</a>
            {' / '}
            <a href="https://x.com/aicuai" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>X@AICUai</a>
            {' / '}
            <Link to="/corp" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>AboutUs</Link>
          </p>
        </footer>
      </main>
    </div>
  );
}

function SectionTitle({ children }) {
  return (
    <h2 style={{
