import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { useNavigate } from 'react-router-dom';

const STEPS = { EMAIL: 'email', SENT: 'sent' };

export default function Login() {
  const { sendOtp, signInWithDiscord, signInWithGoogle, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(STEPS.EMAIL);
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [sending, setSending] = useState(false);

  useEffect(() => {
    if (isAuthenticated) navigate('/', { replace: true });
  }, [isAuthenticated, navigate]);

  const handleSendLink = async (e) => {
    e.preventDefault();
    if (!email.trim()) return;
    setError('');
    setSending(true);
    try {
      await sendOtp(email.trim());
      setStep(STEPS.SENT);
    } catch (err) {
      setError(err.message || 'メール送信に失敗しました');
    }
    setSending(false);
  };

  const handleResend = async () => {
    setError('');
    setSending(true);
    try {
      await sendOtp(email);
      setError('');
    } catch {
      setError('再送信に失敗しました');
    }
    setSending(false);
  };

  return (
    <div style={styles.container}>
      <div style={styles.inner}>
        {/* Logo */}
        <div style={styles.logoArea}>
          <span style={styles.logo}>AICU</span>
          <p style={styles.subtitle}>生成AI時代に「つくる人をつくる」</p>
        </div>

        {/* Email Step */}
        {step === STEPS.EMAIL && (
          <form onSubmit={handleSendLink} style={styles.form}>
            <h2 style={styles.heading}>ログイン / 新規登録</h2>
            <p style={styles.desc}>
              メールアドレスにログインリンクを送信します
            </p>
            <div style={styles.inputGroup}>
              <input
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="you@example.com"
                autoFocus
                autoComplete="email"
                required
                style={styles.emailInput}
              />
            </div>
            {error && <p style={styles.error}>{error}</p>}
            <button
              type="submit"
              disabled={sending || !email.trim()}
              style={{
                ...styles.primaryBtn,
                opacity: (sending || !email.trim()) ? 0.5 : 1,
              }}
            >
              {sending ? '送信中...' : 'ログインリンクを送信'}
            </button>

            {/* Divider */}
            <div style={styles.dividerRow}>
              <div style={styles.dividerLine} />
              <span style={styles.dividerText}>または</span>
              <div style={styles.dividerLine} />
            </div>

            {/* Google OAuth */}
            <button
              type="button"
              onClick={signInWithGoogle}
              style={styles.googleBtn}
            >
              <svg width="18" height="18" viewBox="0 0 24 24">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4"/>
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
              </svg>
              Googleでログイン
            </button>

            {/* Discord OAuth */}
            <button
              type="button"
              onClick={signInWithDiscord}
              style={styles.discordBtn}
            >
              <svg width="20" height="15" viewBox="0 0 71 55" fill="currentColor">
                <path d="M60.1 4.9A58.5 58.5 0 0045.4.2a.2.2 0 00-.2.1 40.8 40.8 0 00-1.8 3.7 54 54 0 00-16.2 0A37.3 37.3 0 0025.4.3a.2.2 0 00-.2-.1A58.4 58.4 0 0010.5 4.9a.2.2 0 00-.1.1C1.5 18.7-.9 32.2.3 45.5v.2a58.9 58.9 0 0017.7 9a.2.2 0 00.3-.1 42.1 42.1 0 003.6-5.9.2.2 0 00-.1-.3 38.8 38.8 0 01-5.5-2.6.2.2 0 01 0-.4l1.1-.9a.2.2 0 01.2 0 42 42 0 0035.6 0 .2.2 0 01.2 0l1.1.9a.2.2 0 010 .4 36.4 36.4 0 01-5.5 2.6.2.2 0 00-.1.3 47.2 47.2 0 003.6 5.9.2.2 0 00.3.1A58.7 58.7 0 0070.5 45.7v-.2c1.4-15-2.3-28-9.8-39.6a.2.2 0 00-.1-.1zM23.7 37.3c-3.4 0-6.3-3.2-6.3-7s2.8-7 6.3-7 6.4 3.1 6.3 7-2.8 7-6.3 7zm23.2 0c-3.4 0-6.3-3.2-6.3-7s2.8-7 6.3-7 6.4 3.1 6.3 7-2.8 7-6.3 7z"/>
              </svg>
              Discordでログイン
            </button>

            <p style={styles.terms}>
              続行することで以下に同意したものとみなします<br />
              <a href="https://www.aicu.blog/terms/plan-free" target="_blank" rel="noopener" style={styles.link}>利用規約</a>
              {' / '}
              <a href="https://corp.aicu.ai/ja/privacy" target="_blank" rel="noopener" style={styles.link}>プライバシー</a>
              {' / '}
              <a href="https://www.aicu.blog/terms/legal" target="_blank" rel="noopener" style={styles.link}>法的免責</a>
            </p>
          </form>
        )}

        {/* Magic Link Sent Step */}
        {step === STEPS.SENT && (
          <div style={styles.form}>
            <div style={{ textAlign: 'center', marginBottom: 16 }}>
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="var(--aicu-rose)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <rect x="2" y="4" width="20" height="16" rx="2"/>
                <path d="M22 4l-10 8L2 4"/>
              </svg>
            </div>
            <h2 style={styles.heading}>メールを確認してください</h2>
            <p style={styles.desc}>
              <strong style={{ color: 'var(--text-primary)' }}>{email}</strong>
              <br />にログインリンクを送信しました。
              <br />メール内の「Log In」ボタンをタップしてください。
            </p>
            <p style={{
              fontSize: 12,
              color: 'var(--text-tertiary)',
              textAlign: 'center',
              marginBottom: 20,
              lineHeight: 1.6,
            }}>
              メールが届かない場合は迷惑メールフォルダもご確認ください
            </p>
            {error && <p style={styles.error}>{error}</p>}
            <div style={styles.resendRow}>
              <button onClick={handleResend} disabled={sending} style={styles.textBtn}>
                {sending ? '送信中...' : 'リンクを再送信'}
              </button>
              <span style={styles.divider}>·</span>
              <button
                onClick={() => { setStep(STEPS.EMAIL); setError(''); }}
                style={styles.textBtn}
              >
                メールアドレスを変更
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

