                <path d="M60.1 4.9A58.5 58.5 0 0045.4.2a.2.2 0 00-.2.1 40.8 40.8 0 00-1.8 3.7 54 54 0 00-16.2 0A37.3 37.3 0 0025.4.3a.2.2 0 00-.2-.1A58.4 58.4 0 0010.5 4.9a.2.2 0 00-.1.1C1.5 18.7-.9 32.2.3 45.5v.2a58.9 58.9 0 0017.7 9a.2.2 0 00.3-.1 42.1 42.1 0 003.6-5.9.2.2 0 00-.1-.3 38.8 38.8 0 01-5.5-2.6.2.2 0 01 0-.4l1.1-.9a.2.2 0 01.2 0 42 42 0 0035.6 0 .2.2 0 01.2 0l1.1.9a.2.2 0 010 .4 36.4 36.4 0 01-5.5 2.6.2.2 0 00-.1.3 47.2 47.2 0 003.6 5.9.2.2 0 00.3.1A58.7 58.7 0 0070.5 45.7v-.2c1.4-15-2.3-28-9.8-39.6a.2.2 0 00-.1-.1zM23.7 37.3c-3.4 0-6.3-3.2-6.3-7s2.8-7 6.3-7 6.4 3.1 6.3 7-2.8 7-6.3 7zm23.2 0c-3.4 0-6.3-3.2-6.3-7s2.8-7 6.3-7 6.4 3.1 6.3 7-2.8 7-6.3 7z"/>
              </svg>
              Discordでログイン
            </button>

            <p style={styles.terms}>
              続行することで以下に同意したものとみなします<br />
              <a href="https://www.aicu.blog/terms/plan-free" target="_blank" rel="noopener" style={styles.link}>利用規約</a>
              {' / '}
              <a href="https://corp.aicu.ai/ja/privacy" target="_blank" rel="noopener" style={styles.link}>プライバシー</a>
              {' / '}
              <a href="https://www.aicu.blog/terms/legal" target="_blank" rel="noopener" style={styles.link}>法的免責</a>
            </p>
          </form>
        )}

        {/* Magic Link Sent Step */}
        {step === STEPS.SENT && (
          <div style={styles.form}>
            <div style={{ textAlign: 'center', marginBottom: 16 }}>
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="var(--aicu-rose)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <rect x="2" y="4" width="20" height="16" rx="2"/>
                <path d="M22 4l-10 8L2 4"/>
              </svg>
            </div>
            <h2 style={styles.heading}>メールを確認してください</h2>
            <p style={styles.desc}>
              <strong style={{ color: 'var(--text-primary)' }}>{email}</strong>
              <br />にログインリンクを送信しました。
              <br />メール内の「Log In」ボタンをタップしてください。
            </p>
            <p style={{
              fontSize: 12,
              color: 'var(--text-tertiary)',
              textAlign: 'center',
              marginBottom: 20,
              lineHeight: 1.6,
            }}>
              メールが届かない場合は迷惑メールフォルダもご確認ください
            </p>
            {error && <p style={styles.error}>{error}</p>}
            <div style={styles.resendRow}>
              <button onClick={handleResend} disabled={sending} style={styles.textBtn}>
                {sending ? '送信中...' : 'リンクを再送信'}
              </button>
              <span style={styles.divider}>·</span>
              <button
                onClick={() => { setStep(STEPS.EMAIL); setError(''); }}
                style={styles.textBtn}
              >
                メールアドレスを変更
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
