import { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { useFeed } from '../hooks/useFeed';
import { useArticleActions } from '../hooks/useArticleActions';
import { supabase } from '../utils/supabase';
import { formatDate } from '../utils/rss';

const REACTIONS = [
  { emoji: '👍', label: 'いいね' },
  { emoji: '🔥', label: '熱い' },
  { emoji: '💡', label: '参考になった' },
  { emoji: '🤔', label: 'もっと知りたい' },
];

function trackEvent(action, params) {
  if (window.gtag) window.gtag('event', action, params);
}

export default function News() {
  const { user, isAuthenticated } = useAuth();
  const { articles, loading, updatedAt } = useFeed('aicu');
  const { isRead, markRead, isBookmarked, toggleBookmark, bookmarkCount } = useArticleActions();
  const [displayName, setDisplayName] = useState(null);

  // Fetch display_name from profiles (Supabase)
  useEffect(() => {
    if (!user) return;
    supabase
      .from('profiles')
      .select('display_name')
      .eq('id', user.id)
      .single()
      .then(({ data }) => {
        if (data?.display_name) {
          setDisplayName(data.display_name);
        } else {
          // Fallback: auth metadata name
          setDisplayName(
            user.user_metadata?.full_name
            || user.user_metadata?.name
            || user.email?.split('@')[0]
            || null
          );
        }
      });
  }, [user]);

  const top2 = articles.slice(0, 2);

  const handleOpen = useCallback((article) => {
    markRead(article);
    trackEvent('news_article_click', { article_title: article.title });
    window.open(article.link, '_blank', 'noopener');
  }, [markRead]);

  // Track page view
  useEffect(() => {
    trackEvent('page_view', { page_title: 'AICU News', page_path: '/news' });
  }, []);

  return (
    <div style={{ minHeight: '100vh' }}>
      {/* Header — 1 line: back + greeting + updated */}
      <header style={{
        position: 'sticky',
        top: 0,
        zIndex: 50,
        background: 'var(--bg-nav)',
        backdropFilter: 'blur(20px) saturate(180%)',
        WebkitBackdropFilter: 'blur(20px) saturate(180%)',
        borderBottom: '0.5px solid var(--border)',
      }}>
        <div style={{
          maxWidth: 640,
          margin: '0 auto',
          padding: '10px 16px',
          display: 'flex',
          alignItems: 'center',
          gap: 8,
        }}>
          <Link to="/" style={{
            padding: 4,
            color: 'var(--text-primary)',
            display: 'flex',
            alignItems: 'center',
            flexShrink: 0,
          }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="15 18 9 12 15 6"/>
            </svg>
          </Link>
          <div style={{ flex: 1, minWidth: 0 }}>
            <span style={{
              fontSize: 15,
              fontWeight: 700,
              color: 'var(--text-primary)',
            }}>
              {displayName
                ? <>{displayName}さんへの新着</>
                : <>今日の新着</>
              }
            </span>
            {!displayName && isAuthenticated && (
              <Link to="/profile" style={{
                fontSize: 10,
                color: 'var(--aicu-rose)',
                textDecoration: 'none',
                marginLeft: 6,
              }}>
                名前を設定
              </Link>
            )}
          </div>
          {updatedAt && (
            <span style={{ fontSize: 10, color: 'var(--text-tertiary)', flexShrink: 0, whiteSpace: 'nowrap' }}>
              {formatUpdatedAt(updatedAt)}
            </span>
          )}
        </div>
      </header>

      <main style={{
        maxWidth: 640,
        margin: '0 auto',
        padding: 16,
      }}>
        {/* Loading */}
        {loading && !top2.length && (
          <div style={{ padding: 32, textAlign: 'center', color: 'var(--text-tertiary)' }}>
            読み込み中...
          </div>
        )}

        {/* Articles */}
        {top2.map((article, i) => (
          <NewsCard
            key={article.id}
            article={article}
            index={i}
            onOpen={handleOpen}
            isRead={isRead(article.id || article.link)}
            isBookmarked={isBookmarked(article.id || article.link)}
            onBookmark={() => {
              toggleBookmark(article);
              trackEvent('news_bookmark', { article_title: article.title });
            }}
          />
        ))}

        {/* Bookmarks link */}
        <Link
          to="/bookmarks"
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: 8,
            padding: '14px 20px',
            marginTop: 4,
            borderRadius: 12,
            background: 'var(--bg-card)',
            boxShadow: 'var(--shadow-sm)',
            textDecoration: 'none',
            color: 'var(--text-primary)',
            fontSize: 14,
            fontWeight: 600,
          }}
        >
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--aicu-rose)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
          </svg>
          後で読むリスト
          {bookmarkCount > 0 && (
            <span style={{
              fontSize: 11,
              fontWeight: 700,
              color: '#fff',
              background: 'var(--aicu-rose)',
              padding: '2px 8px',
              borderRadius: 10,
            }}>
              {bookmarkCount}
            </span>
          )}
        </Link>

        {/* More articles link */}
        {articles.length > 2 && (
          <Link
            to="/media"
            style={{
              display: 'block',
              textAlign: 'center',
              padding: '14px',
              marginTop: 8,
              borderRadius: 12,
              background: 'var(--bg-card)',
              color: 'var(--aicu-rose)',
              fontSize: 14,
              fontWeight: 600,
              textDecoration: 'none',
              boxShadow: 'var(--shadow-sm)',
            }}
          >
            もっと記事を見る →
          </Link>
        )}

        {/* Login prompt for anonymous */}
        {!isAuthenticated && (
          <div style={{
            marginTop: 20,
            padding: '16px 20px',
            borderRadius: 12,
            background: 'var(--aicu-rose-light)',
            border: '1px solid var(--aicu-rose)',
            textAlign: 'center',
          }}>
            <p style={{ fontSize: 13, color: 'var(--text-primary)', marginBottom: 10, lineHeight: 1.5 }}>
              ログインすると、あなた専用の新着通知が届きます
            </p>
            <Link
              to="/login"
              style={{
                display: 'inline-block',
                padding: '10px 24px',
                borderRadius: 20,
                background: 'var(--aicu-rose)',
                color: '#fff',
                fontSize: 14,
                fontWeight: 600,
                textDecoration: 'none',
              }}
            >
              ログイン / 新規登録
            </Link>
          </div>
        )}

        {/* Footer */}
        <footer style={{
          padding: '24px 0',
          textAlign: 'center',
          fontSize: 11,
          color: 'var(--text-tertiary)',
        }}>
          <a href="https://note.com/aicu" target="_blank" rel="noopener" style={{ color: 'var(--aicu-rose)', textDecoration: 'none' }}>
            AICU media on note.com
          </a>
        </footer>
      </main>
    </div>
  );
}

function NewsCard({ article, index, onOpen, isRead, isBookmarked, onBookmark }) {
  const [reacted, setReacted] = useState(() => {
    try {
      const saved = JSON.parse(localStorage.getItem('news_reactions') || '{}');
      return saved[article.id || article.link] || null;
    } catch { return null; }
  });

  const handleReaction = (emoji) => {
    const key = article.id || article.link;
    const next = reacted === emoji ? null : emoji;
    setReacted(next);
    trackEvent('news_reaction', { article_title: article.title, reaction: emoji });
    try {
      const saved = JSON.parse(localStorage.getItem('news_reactions') || '{}');
      if (next) saved[key] = next;
      else delete saved[key];
      localStorage.setItem('news_reactions', JSON.stringify(saved));
    } catch {}
  };

  return (
    <div style={{
      background: 'var(--bg-card)',
      borderRadius: 16,
      overflow: 'hidden',
      boxShadow: 'var(--shadow-sm)',
      marginBottom: 16,
    }}>
      {/* Thumbnail */}
      {article.thumbnail && (
        <div
          style={{ cursor: 'pointer', overflow: 'hidden' }}
          onClick={() => onOpen(article)}
        >
          <img
            src={article.thumbnail}
            alt=""
            loading={index === 0 ? 'eager' : 'lazy'}
            style={{
              width: '100%',
              aspectRatio: '16/9',
              objectFit: 'cover',
              display: 'block',
              opacity: isRead ? 0.6 : 1,
              transition: 'opacity 0.2s',
            }}
            onError={e => { e.target.style.display = 'none'; }}
          />
        </div>
      )}

      {/* Content */}
      <div style={{ padding: '14px 16px' }}>
        {/* Top row: badge + bookmark */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
          <div style={{
            display: 'inline-block',
            padding: '2px 8px',
            borderRadius: 6,
            background: index === 0 ? 'var(--aicu-rose)' : 'var(--bg-primary)',
            color: index === 0 ? '#fff' : 'var(--text-secondary)',
            fontSize: 10,
            fontWeight: 700,
          }}>
            {index === 0 ? 'NEW' : `#${index + 1}`}
          </div>
          <button
            onClick={onBookmark}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 4,
              background: isBookmarked ? 'var(--aicu-rose-light)' : 'var(--bg-primary)',
              border: isBookmarked ? '1.5px solid var(--aicu-rose)' : '1px solid var(--border)',
              borderRadius: 20,
              padding: '5px 12px',
              cursor: 'pointer',
              color: isBookmarked ? 'var(--aicu-rose)' : 'var(--text-secondary)',
              fontSize: 12,
              fontWeight: isBookmarked ? 600 : 400,
              transition: 'all 0.15s',
            }}
          >
            <svg width="16" height="16" viewBox="0 0 24 24"
              fill={isBookmarked ? 'currentColor' : 'none'}
              stroke="currentColor" strokeWidth="2"
            >
              <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
            </svg>
            {isBookmarked ? '保存済み' : '後で読む'}
          </button>
        </div>

        <h2
          style={{
            fontSize: 16,
            fontWeight: 700,
            lineHeight: 1.5,
            color: isRead ? 'var(--text-tertiary)' : 'var(--text-primary)',
            cursor: 'pointer',
            marginBottom: 6,
          }}
          onClick={() => onOpen(article)}
        >
          {article.title}
        </h2>

        {article.description && (
          <p style={{
            fontSize: 13,
            color: 'var(--text-secondary)',
            lineHeight: 1.6,
            marginBottom: 10,
            display: '-webkit-box',
            WebkitLineClamp: 3,
            WebkitBoxOrient: 'vertical',
            overflow: 'hidden',
          }}>
            {article.description}
          </p>
        )}

        {/* Date */}
        <time style={{ fontSize: 12, color: 'var(--text-tertiary)', display: 'block', marginBottom: 10 }}>
          {formatDate(article.pubDate)}
        </time>

        {/* Reaction bar */}
        <div style={{
          display: 'flex',
          gap: 6,
          flexWrap: 'wrap',
        }}>
          {REACTIONS.map(r => (
            <button
              key={r.emoji}
              onClick={() => handleReaction(r.emoji)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 4,
                padding: '6px 10px',
                borderRadius: 20,
                border: reacted === r.emoji
                  ? '1.5px solid var(--aicu-rose)'
                  : '1px solid var(--border)',
                background: reacted === r.emoji
                  ? 'var(--aicu-rose-light)'
                  : 'var(--bg-primary)',
                cursor: 'pointer',
                fontSize: 12,
                color: reacted === r.emoji
                  ? 'var(--aicu-rose)'
                  : 'var(--text-secondary)',
                fontWeight: reacted === r.emoji ? 600 : 400,
                transition: 'all 0.15s',
              }}
            >
              <span>{r.emoji}</span>
              <span>{r.label}</span>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

function formatUpdatedAt(iso) {
  const d = new Date(iso);
  if (isNaN(d)) return '';
  return `${d.getMonth() + 1}/${d.getDate()} ${d.getHours()}:${String(d.getMinutes()).padStart(2, '0')}`;
}

