 17→// ---------------------------------------------------------------------------
 18→// Crypto helpers (Web Crypto API)
 19→// ---------------------------------------------------------------------------
 20→async function md5Hex(text) {
 21→  const data = new TextEncoder().encode(text);
 22→  const hash = await crypto.subtle.digest('MD5', data);
 23→  return [...new Uint8Array(hash)].map(b => b.toString(16).padStart(2, '0')).join('');
