 29→function dateToYYMMDD(isoDate) {
 30→  const d = new Date(isoDate);
 31→  const jst = new Date(d.getTime() + 9 * 60 * 60 * 1000);
 32→  const yy = String(jst.getUTCFullYear()).slice(-2);
 33→  const mm = String(jst.getUTCMonth() + 1).padStart(2, '0');
 34→  const dd = String(jst.getUTCDate()).padStart(2, '0');
