 38→function extFromUrl(url) {
 39→  try {
 40→    const pathname = new URL(url).pathname;
 41→    const ext = pathname.split('.').pop().toLowerCase();
 42→    if (['png', 'jpg', 'jpeg', 'webp', 'gif'].includes(ext)) return ext;
