 50→function parseRSS(xml) {
 51→  const items = [];
 52→  const itemRegex = /<item>([\s\S]*?)<\/item>/g;
 53→  let match;
 54→
 55→  while ((match = itemRegex.exec(xml)) !== null) {
 56→    const block = match[1];
 57→    const get = (tag) => {
 58→      const m = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`));
 59→      return m ? m[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').trim() : '';
 60→    };
