/**
 * aicu-feed-updater — Cloudflare Workers Cron
 *
 * Runs every 3 hours (covers 6:00 JST = 21:00 UTC).
 * 1. Fetch note.com RSS
 * 2. Compare MD5 hash with stored value in R2
 * 3. If changed: parse articles, upload new thumbnails, update feed JSON
 *
 * R2 layout:
 *   note/YYMMDD.png       — thumbnail images
 *   data/feed-aicu.json   — feed JSON (served by Pages Function)
 *   meta/rss-hash.txt     — MD5 of last processed RSS
 */

const RSS_URL = 'https://note.com/aicu/rss';

// ---------------------------------------------------------------------------
// Crypto helpers (Web Crypto API)
// ---------------------------------------------------------------------------
async function md5Hex(text) {
  const data = new TextEncoder().encode(text);
  const hash = await crypto.subtle.digest('MD5', data);
  return [...new Uint8Array(hash)].map(b => b.toString(16).padStart(2, '0')).join('');
}

// ---------------------------------------------------------------------------
// Date helpers
// ---------------------------------------------------------------------------
function dateToYYMMDD(isoDate) {
  const d = new Date(isoDate);
  const jst = new Date(d.getTime() + 9 * 60 * 60 * 1000);
  const yy = String(jst.getUTCFullYear()).slice(-2);
  const mm = String(jst.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(jst.getUTCDate()).padStart(2, '0');
  return `${yy}${mm}${dd}`;
}

function extFromUrl(url) {
  try {
    const pathname = new URL(url).pathname;
    const ext = pathname.split('.').pop().toLowerCase();
    if (['png', 'jpg', 'jpeg', 'webp', 'gif'].includes(ext)) return ext;
  } catch {}
  return 'png';
}

// ---------------------------------------------------------------------------
// Minimal XML parser (no dependencies, handles note.com RSS)
// ---------------------------------------------------------------------------
function parseRSS(xml) {
  const items = [];
  const itemRegex = /<item>([\s\S]*?)<\/item>/g;
  let match;

  while ((match = itemRegex.exec(xml)) !== null) {
    const block = match[1];
    const get = (tag) => {
      const m = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`));
      return m ? m[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').trim() : '';
    };

    const title = get('title');
    const link = get('link');
    const guid = get('guid') || link;
    const pubDateRaw = get('pubDate');
    const pubDate = pubDateRaw ? new Date(pubDateRaw).toISOString() : '';
    const rawDesc = get('description');
    const creator = get('note:creatorName') || 'AICU';

    // media:thumbnail — note.com puts URL as text content
    let thumbnail = '';
    const thumbMatch = block.match(/<media:thumbnail[^>]*>([^<]+)<\/media:thumbnail>/);
    if (thumbMatch) {
      thumbnail = thumbMatch[1].trim();
    } else {
      // Try url attribute fallback
      const attrMatch = block.match(/<media:thumbnail[^>]+url="([^"]+)"/);
      if (attrMatch) thumbnail = attrMatch[1].trim();
    }

    // Strip HTML from description
    const plainDesc = rawDesc
      .replace(/<[^>]+>/g, '')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/続きをみる$/, '')
      .trim()
      .slice(0, 200);

    items.push({ id: guid, title, link, pubDate, description: plainDesc, thumbnail, creator });
  }

  return items;
}

// ---------------------------------------------------------------------------
// R2 helpers
// ---------------------------------------------------------------------------
async function r2GetText(bucket, key) {
  const obj = await bucket.get(key);
  if (!obj) return null;
  return obj.text();
}

async function r2Exists(bucket, key) {
  const head = await bucket.head(key);
  return head !== null;
}

const CONTENT_TYPES = {
  png: 'image/png', jpg: 'image/jpeg', jpeg: 'image/jpeg',
  webp: 'image/webp', gif: 'image/gif',
};

async function uploadThumbnail(bucket, imageUrl, yymmdd) {
  const ext = extFromUrl(imageUrl);
  const key = `note/${yymmdd}.${ext}`;

  if (await r2Exists(bucket, key)) {
    return `/img/note/${yymmdd}.${ext}`;
  }

  const res = await fetch(imageUrl);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  const body = await res.arrayBuffer();

  await bucket.put(key, body, {
    httpMetadata: {
      contentType: CONTENT_TYPES[ext] || 'application/octet-stream',
      cacheControl: 'public, max-age=31536000, immutable',
    },
  });

  return `/img/note/${yymmdd}.${ext}`;
}

// ---------------------------------------------------------------------------
// Main logic
// ---------------------------------------------------------------------------
async function updateFeed(env) {
  const bucket = env.MEDIA;

  // 1. Fetch RSS
  const rssRes = await fetch(RSS_URL);
  if (!rssRes.ok) throw new Error(`RSS fetch failed: ${rssRes.status}`);
  const rssXml = await rssRes.text();

  // 2. Hash check
  const newHash = await md5Hex(rssXml);
  const oldHash = await r2GetText(bucket, 'meta/rss-hash.txt');

  if (newHash === oldHash) {
    console.log('No changes detected (hash match). Skipping.');
    return { updated: false, hash: newHash };
  }
  console.log(`Change detected! old=${oldHash || '(none)'} new=${newHash}`);

  // 3. Parse
  const items = parseRSS(rssXml);
  console.log(`Parsed ${items.length} articles`);

  // 4. Assign YYMMDD names
  const dateCount = {};
  for (const item of items) {
    if (!item.pubDate) continue;
    const base = dateToYYMMDD(item.pubDate);
    dateCount[base] = (dateCount[base] || 0) + 1;
    item._yymmdd = dateCount[base] === 1 ? base : `${base}-${dateCount[base]}`;
  }

  // 5. Upload thumbnails
  let uploaded = 0;
  for (const item of items) {
    if (!item.thumbnail || !item._yymmdd) continue;
    try {
      const oldUrl = item.thumbnail;
      item.thumbnail = await uploadThumbnail(bucket, oldUrl, item._yymmdd);
      uploaded++;
    } catch (err) {
      console.error(`Failed: ${item._yymmdd} — ${err.message}`);
      // Keep original URL
    }
  }
  console.log(`Thumbnails processed: ${uploaded}/${items.length}`);

  // 6. Write feed JSON to R2
  const output = items.map(({ _yymmdd, ...rest }) => rest);
  const feed = { updatedAt: new Date().toISOString(), articles: output };
  await bucket.put('data/feed-aicu.json', JSON.stringify(feed, null, 2), {
    httpMetadata: {
      contentType: 'application/json',
      cacheControl: 'public, max-age=300',
    },
  });

  // 7. Save hash
  await bucket.put('meta/rss-hash.txt', newHash, {
    httpMetadata: { contentType: 'text/plain' },
  });

  console.log('Feed updated successfully.');
  return { updated: true, hash: newHash, articles: items.length, uploaded };
}

// ---------------------------------------------------------------------------
// Daily push notification (12:00 JST = 03:00 UTC)
// ---------------------------------------------------------------------------
async function sendDailyPush(env) {
  const bucket = env.MEDIA;
  const apiUrl = env.PUSH_API_URL;
  const apiKey = env.CRON_API_KEY;

  if (!apiUrl || !apiKey) {
    console.log('PUSH_API_URL or CRON_API_KEY not configured. Skipping push.');
    return { pushed: false, reason: 'not configured' };
  }

  // Read latest feed from R2
  const feedObj = await bucket.get('data/feed-aicu.json');
  if (!feedObj) {
    console.log('No feed JSON in R2. Skipping push.');
    return { pushed: false, reason: 'no feed' };
  }

  const feed = JSON.parse(await feedObj.text());
  const articles = feed.articles || [];
  if (articles.length === 0) {
    return { pushed: false, reason: 'no articles' };
  }

  const a1 = articles[0];
  const a2 = articles.length > 1 ? articles[1] : null;
  const title = a1.title;
  const body = a2 ? `${a1.title}／${a2.title}` : a1.title;
  const url = 'https://aicu.jp/news';

  const res = await fetch(apiUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Cron-Key': apiKey,
    },
    body: JSON.stringify({ title, body, url }),
  });

  const result = await res.json();
  console.log(`Push notification sent: ${JSON.stringify(result)}`);
  return { pushed: true, ...result };
}

// ---------------------------------------------------------------------------
// Worker entry
// ---------------------------------------------------------------------------
export default {
  // Cron trigger
  async scheduled(event, env, ctx) {
    // Always update feed
    ctx.waitUntil(updateFeed(env));

    // Daily push at 02:55 UTC (11:55 JST)
    const t = new Date(event.scheduledTime);
    if (t.getUTCHours() === 2 && t.getUTCMinutes() === 55) {
      ctx.waitUntil(sendDailyPush(env));
    }
  },

  // HTTP trigger (manual / debug)
  async fetch(request, env) {
    const url = new URL(request.url);

    // POST /push — manual push trigger
    if (request.method === 'POST' && url.pathname === '/push') {
      try {
        const result = await sendDailyPush(env);
        return Response.json(result);
      } catch (err) {
        return Response.json({ error: err.message }, { status: 500 });
      }
    }

    // POST — feed update trigger
    if (request.method === 'POST') {
      try {
        const result = await updateFeed(env);
        return Response.json(result);
      } catch (err) {
        return Response.json({ error: err.message }, { status: 500 });
      }
    }

    return new Response('POST to trigger feed update. POST /push to trigger daily notification.', { status: 200 });
  },
};
